10	import org.springframework.web.bind.annotation.*;
11	
12	import java.time.LocalDateTime;
13	import java.util.List;
14	
15	/**
16	 * 环境数据接口
17	 */
18	@RestController
19	@RequestMapping("/environment")
20	@RequiredArgsConstructor
21	@Slf4j
22	public class EnvironmentController {
23	
24	    private final SensorDataService sensorDataService;
25	
26	    /**
27	     * 获取当前环境数据
28	     */
29	    @GetMapping
30	    public ApiResponse<EnvironmentDataDTO> getCurrentData(
31	            @RequestParam(required = false, defaultValue = "1") Long pointId) {
32	        EnvironmentDataDTO data = sensorDataService.getCurrentData(pointId);
33	        if (data == null) {
34	            return ApiResponse.error("暂无数据");
35	        }
36	        return ApiResponse.success(data);
37	    }
38	
39	    /**
40	     * 获取历史数据
41	     */
42	    @GetMapping("/history")
43	    public ApiResponse<List<EnvironmentDataDTO>> getHistoryData(
44	            @RequestParam(required = false, defaultValue = "1") Long pointId,
45	            @RequestParam(required = false, defaultValue = "100") int limit) {
46	        List<EnvironmentDataDTO> data = sensorDataService.getHistoryData(pointId, limit);
47	        return ApiResponse.success(data);
48	    }
49	
50	    /**
51	     * 分页获取历史数据
52	     */
53	    @GetMapping("/history/paged")
54	    public ApiResponse<Page<EnvironmentDataDTO>> getHistoryDataPaged(
55	            @RequestParam(required = false, defaultValue = "1") Long pointId,
56	            @RequestParam(required = false, defaultValue = "0") int page,
57	            @RequestParam(required = false, defaultValue = "20") int size) {
58	        Page<EnvironmentDataDTO> data = sensorDataService.getHistoryDataPaged(pointId, page, size);
59	        return ApiResponse.success(data);
60	    }
61	
62	    /**
63	     * 按时间范围查询
64	     */
65	    @GetMapping("/history/range")
66	    public ApiResponse<List<EnvironmentDataDTO>> getHistoryDataByTimeRange(
67	            @RequestParam(required = false, defaultValue = "1") Long pointId,
68	            @RequestParam @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime startTime,
69	            @RequestParam @DateTimeFormat(pattern = "yyyy-MM-dd HH:mm:ss") LocalDateTime endTime) {
70	        List<EnvironmentDataDTO> data = sensorDataService.getHistoryDataByTimeRange(pointId, startTime, endTime);
71	        return ApiResponse.success(data);
72	    }
73	
74	    /**
75	     * 上报环境数据（网关用）
76	     */
77	    @PostMapping
78	    public ApiResponse<EnvironmentDataDTO> uploadData(@RequestBody EnvironmentDataDTO dto) {
79	        EnvironmentDataDTO saved = sensorDataService.saveData(dto);
80	        return ApiResponse.success("数据上报成功", saved);
81	    }
82	}
