193	    @PostMapping("/smart-irrigation/simulate")
194	    public ApiResponse<Map<String, Object>> simulateIrrigation(
195	            @RequestParam(defaultValue = "1") Long pointId,
196	            @RequestParam(defaultValue = "35") BigDecimal soilMoistureBefore) {
197	        Map<String, Object> result = new HashMap<>();
198	
199	        // 1. 构造环境数据
200	        EnvironmentDataDTO envData = new EnvironmentDataDTO();
201	        envData.setPointId(pointId);
202	        envData.setSoilMoisture(soilMoistureBefore);
203	        envData.setTemperature(BigDecimal.valueOf(28));
204	        envData.setHumidity(BigDecimal.valueOf(50));
205	        envData.setLight(BigDecimal.valueOf(30000));
206	
207	        // 2. 生成灌溉计划
208	        SmartIrrigationPlanDTO plan = smartIrrigationService.buildSmartPlan(pointId, envData, null);
209	        result.put("plan", plan);
210	
211	        if (!Boolean.TRUE.equals(plan.getShouldIrrigate())) {
212	            result.put("message", "无需灌溉: " + plan.getReason());
213	            return ApiResponse.success(result);
214	        }
215	
216	        // 3. 执行灌溉
217	        IrrigationLog log = smartIrrigationService.executeSmartIrrigation(pointId, plan, envData);
218	        result.put("irrigationLog", log);
219	
220	        // 4. 模拟灌溉效果（假设每升水提升 1.5% 湿度）
221	        BigDecimal actualGain = plan.getWaterAmountL().multiply(BigDecimal.valueOf(1.5));
222	        BigDecimal soilMoistureAfter = soilMoistureBefore.add(actualGain);
223	        result.put("simulatedMoistureAfter", soilMoistureAfter);
224	
225	        // 5. 触发学习
226	        smartIrrigationService.onIrrigationComplete(log.getId(), soilMoistureAfter);
