237	    /**
238	     * 批量生成传感器历史数据（用于预测算法）
239	     */
240	    @PostMapping("/smart-irrigation/generate-history")
241	    public ApiResponse<String> generateHistoryData(
242	            @RequestParam(defaultValue = "1") Long pointId,
243	            @RequestParam(defaultValue = "24") int hours,
244	            @RequestParam(defaultValue = "falling") String trend) {
245	
246	        Random random = new Random();
247	        LocalDateTime now = LocalDateTime.now();
248	
249	        // 基础湿度
250	        double baseMoisture = 55;
251	        // 趋势变化率
252	        double trendRate = "falling".equals(trend) ? -0.5 : ("rising".equals(trend) ? 0.3 : 0);
253	
254	        for (int i = hours; i >= 0; i--) {
255	            EnvironmentDataDTO dto = new EnvironmentDataDTO();
256	            dto.setPointId(pointId);
257	            dto.setRecordedAt(now.minusHours(i));
258	
259	            // 按趋势变化的湿度
260	            double moisture = baseMoisture + (hours - i) * trendRate + (random.nextDouble() - 0.5) * 3;
261	            moisture = Math.max(20, Math.min(80, moisture));
262	
263	            dto.setSoilMoisture(BigDecimal.valueOf(moisture).setScale(2, RoundingMode.HALF_UP));
264	            dto.setTemperature(BigDecimal.valueOf(20 + random.nextDouble() * 12).setScale(2, RoundingMode.HALF_UP));
265	            dto.setHumidity(BigDecimal.valueOf(45 + random.nextDouble() * 30).setScale(2, RoundingMode.HALF_UP));
266	            dto.setLight(BigDecimal.valueOf(5000 + random.nextDouble() * 30000).setScale(2, RoundingMode.HALF_UP));
267	            dto.setCo2(BigDecimal.valueOf(350 + random.nextDouble() * 300).setScale(2, RoundingMode.HALF_UP));
268	
269	            sensorDataService.saveData(dto);
270	        }
271	
272	        return ApiResponse.success("已生成 " + (hours + 1) + " 小时的历史数据，趋势: " + trend);
273	    }
