278	    @GetMapping("/smart-irrigation/history")
279	    public ApiResponse<Map<String, Object>> getIrrigationHistory(
280	            @RequestParam(defaultValue = "1") Long pointId,
281	            @RequestParam(defaultValue = "10") int limit) {
282	        Map<String, Object> result = new HashMap<>();
283	
284	        // 查询灌溉记录
285	        LambdaQueryWrapper<IrrigationLog> wrapper = new LambdaQueryWrapper<>();
286	        wrapper.eq(IrrigationLog::getPointId, pointId)
287	               .orderByDesc(IrrigationLog::getStartTime)
288	               .last("LIMIT " + limit);
289	        List<IrrigationLog> logs = irrigationLogMapper.selectList(wrapper);
290	        result.put("irrigationLogs", logs);
291	
292	        // 统计
293	        int count = logs.size();
294	        double totalWater = logs.stream()
295	                .filter(l -> l.getWaterAmount() != null)
296	                .mapToDouble(l -> l.getWaterAmount().doubleValue())
297	                .sum();
298	        double avgWater = count > 0 ? totalWater / count : 0;
299	
300	        result.put("stats", Map.of(
301	            "count", count,
302	            "totalWater", BigDecimal.valueOf(totalWater).setScale(2, RoundingMode.HALF_UP),
303	            "avgWater", BigDecimal.valueOf(avgWater).setScale(2, RoundingMode.HALF_UP)
304	        ));
305	
306	        return ApiResponse.success(result);
307	    }
