1	package com.agriculture.service;
2	
3	import com.agriculture.entity.SensorData;
4	import com.agriculture.mapper.SensorDataMapper;
5	import com.agriculture.model.dto.MoisturePredictionDTO;
6	import lombok.RequiredArgsConstructor;
7	import lombok.extern.slf4j.Slf4j;
8	import org.springframework.stereotype.Service;
9	
10	import java.math.BigDecimal;
11	import java.math.RoundingMode;
12	import java.time.LocalDateTime;
13	import java.util.List;
14	import java.util.stream.Collectors;
15	
16	/**
17	 * EWMA湿度预测服务
18	 * 使用指数加权移动平均进行湿度趋势预测
19	 * 直接从 sensor_data 表读取历史数据，无需额外建表
20	 */
21	@Slf4j
22	@Service
23	@RequiredArgsConstructor
24	public class MoisturePredictor {
25	
26	    private final SensorDataMapper sensorDataMapper;
27	
28	    // EWMA衰减因子，越大越重视近期数据
29	    private static final double ALPHA = 0.3;
30	
31	    // 趋势计算窗口大小
32	    private static final int TREND_WINDOW = 3;
33	
34	    /**
35	     * 预测未来湿度变化
36	     *
37	     * @param pointId    检测点ID
38	     * @param hoursAhead 预测未来几小时
39	     * @return 预测结果
40	     */
41	    public MoisturePredictionDTO predict(Long pointId, int hoursAhead) {
42	        MoisturePredictionDTO result = new MoisturePredictionDTO();
43	
44	        // 获取过去24小时的历史数据（从sensor_data表）
45	        LocalDateTime startTime = LocalDateTime.now().minusHours(24);
46	        LocalDateTime endTime = LocalDateTime.now();
47	        List<SensorData> sensorDataList = sensorDataMapper.findByPointIdAndTimeRange(pointId, startTime, endTime);
48	
49	        if (sensorDataList == null || sensorDataList.isEmpty()) {
50	            result.setNeedPreIrrigation(false);
51	            result.setReason("无历史数据，无法预测");
52	            result.setConfidence(BigDecimal.ZERO);
53	            return result;
54	        }
55	
56	        // 提取土壤湿度值（按时间正序排列）
57	        List<Double> history = sensorDataList.stream()
58	                .sorted((a, b) -> a.getRecordedAt().compareTo(b.getRecordedAt()))
59	                .map(d -> d.getSoilMoisture().doubleValue())
60	                .collect(Collectors.toList());
61	
62	        // 计算EWMA平滑值
63	        double ewma = calculateEWMA(history);
64	
65	        // 计算趋势
66	        double trend = calculateTrend(history);
67	
68	        // 当前湿度
69	        double current = history.get(history.size() - 1);
70	        result.setCurrentMoisture(BigDecimal.valueOf(current).setScale(1, RoundingMode.HALF_UP));
71	
72	        // 预测未来值
73	        double predict2h = ewma + trend * 2;
74	        double predict4h = ewma + trend * 4;
75	        double predict6h = ewma + trend * 6;
76	
77	        result.setPredict2h(BigDecimal.valueOf(predict2h).setScale(1, RoundingMode.HALF_UP));
78	        result.setPredict4h(BigDecimal.valueOf(predict4h).setScale(1, RoundingMode.HALF_UP));
79	        result.setPredict6h(BigDecimal.valueOf(predict6h).setScale(1, RoundingMode.HALF_UP));
80	
81	        // 判断趋势
82	        if (trend > 0.5) {
83	            result.setTrend("rising");
84	        } else if (trend < -0.5) {
85	            result.setTrend("falling");
86	        } else {
87	            result.setTrend("stable");
88	        }
89	
90	        // 计算置信度（基于数据量）
91	        double confidence = Math.min(0.9, 0.3 + history.size() * 0.02);
92	        result.setConfidence(BigDecimal.valueOf(confidence).setScale(2, RoundingMode.HALF_UP));
93	
94	        return result;
95	    }
96	
97	    /**
98	     * 分析是否需要预防性灌溉
99	     *
100	     * @param pointId   检测点ID
101	     * @param threshold 湿度阈值
102	     * @return 预测分析结果
103	     */
104	    public MoisturePredictionDTO analyze(Long pointId, double threshold) {
105	        MoisturePredictionDTO result = predict(pointId, 4);
106	
107	        if (result.getCurrentMoisture() == null) {
108	            return result;
109	        }
110	
111	        double current = result.getCurrentMoisture().doubleValue();
112	        double predict2h = result.getPredict2h() != null ? result.getPredict2h().doubleValue() : current;
113	        double predict4h = result.getPredict4h() != null ? result.getPredict4h().doubleValue() : current;
114	
115	        // 下降趋势且预测值低于阈值
116	        if ("falling".equals(result.getTrend()) && predict2h < threshold && current >= threshold) {
117	            result.setNeedPreIrrigation(true);
118	            result.setReason(String.format("预测2小时后湿度将降至%.1f%%，建议提前灌溉", predict2h));
119	        } else if (predict4h < threshold * 0.9) {
120	            // 预测值接近危险线
121	            result.setNeedPreIrrigation(true);
122	            result.setReason(String.format("预测4小时后湿度将降至%.1f%%，接近临界值", predict4h));
123	        } else {
124	            result.setNeedPreIrrigation(false);
125	            if (current < threshold) {
126	                result.setReason("当前湿度已低于阈值，需要立即灌溉");
127	            } else {
128	                result.setReason("湿度正常，无需预防性灌溉");
129	            }
130	        }
131	
132	        return result;
133	    }
134	
135	    /**
136	     * 预测指定小时后的湿度
137	     *
138	     * @param pointId    检测点ID
139	     * @param hoursAhead 预测时长
140	     * @return 预测湿度值
141	     */
142	    public double predictValue(Long pointId, int hoursAhead) {
143	        LocalDateTime startTime = LocalDateTime.now().minusHours(24);
144	        LocalDateTime endTime = LocalDateTime.now();
145	        List<SensorData> sensorDataList = sensorDataMapper.findByPointIdAndTimeRange(pointId, startTime, endTime);
146	
147	        if (sensorDataList == null || sensorDataList.isEmpty()) {
148	            return -1;
149	        }
150	
151	        List<Double> history = sensorDataList.stream()
152	                .sorted((a, b) -> a.getRecordedAt().compareTo(b.getRecordedAt()))
153	                .map(d -> d.getSoilMoisture().doubleValue())
154	                .collect(Collectors.toList());
155	
156	        double ewma = calculateEWMA(history);
157	        double trend = calculateTrend(history);
158	
159	        return ewma + trend * hoursAhead;
160	    }
161	
162	    /**
163	     * 计算EWMA平滑值
164	     */
165	    private double calculateEWMA(List<Double> history) {
166	        if (history.isEmpty()) return 0;
167	
168	        double ewma = history.get(0);
169	        for (int i = 1; i < history.size(); i++) {
170	            ewma = ALPHA * history.get(i) + (1 - ALPHA) * ewma;
171	        }
172	        return ewma;
173	    }
174	
175	    /**
176	     * 计算趋势（最近几个点的平均变化率）
177	     */
178	    private double calculateTrend(List<Double> history) {
179	        if (history.size() < 2) return 0;
180	
181	        int window = Math.min(TREND_WINDOW, history.size() - 1);
182	        double trend = 0;
183	
184	        for (int i = history.size() - window; i < history.size(); i++) {
185	            trend += history.get(i) - history.get(i - 1);
186	        }
187	
188	        return trend / window;
189	    }
190	}

1	package com.agriculture.service;
2	
3	import lombok.Data;
4	import lombok.extern.slf4j.Slf4j;
5	import org.springframework.stereotype.Service;
6	
7	import java.math.BigDecimal;
8	import java.math.RoundingMode;
9	import java.util.*;
10	import java.util.stream.Collectors;
11	
12	/**
13	 * 多目标优化服务
14	 * 使用遗传算法（NSGA-II）优化灌溉决策
15	 * 
16	 * 优化目标：
17	 * 1. 湿度达标率最大化
18	 * 2. 用水量最小化
19	 * 3. 灌溉成本最小化（考虑峰谷电价）
20	 * 4. 作物健康最大化（避免湿度波动）
21	 */
22	@Slf4j
23	@Service
24	public class MultiObjectiveOptimizer {
25	
26	    // 遗传算法参数
27	    private static final int POPULATION_SIZE = 50;
28	    private static final int MAX_GENERATIONS = 100;
29	    private static final double MUTATION_RATE = 0.1;
30	    private static final double CROSSOVER_RATE = 0.8;
31	
32	    // 约束参数
33	    private static final double MIN_WATER = 1.0;
34	    private static final double MAX_WATER = 50.0;
35	    private static final int MIN_DURATION = 10;
36	    private static final int MAX_DURATION = 180;
37	
38	    // 峰谷电价时段（简化模型）
39	    private static final int[] PEAK_HOURS = {9, 10, 11, 14, 15, 16, 17, 18, 19}; // 高峰时段
40	    private static final double PEAK_PRICE = 1.2;
41	    private static final double NORMAL_PRICE = 1.0;
42	    private static final double VALLEY_PRICE = 0.6;
43	
44	    /**
45	     * 优化灌溉方案
46	     * 
47	     * @param currentMoisture 当前土壤湿度
48	     * @param targetMoisture 目标湿度
49	     * @param temperature 当前温度
50	     * @param currentHour 当前小时（用于电价计算）
51	     * @param cropFactor 作物灌溉系数
52	     * @return 优化后的灌溉方案
53	     */
54	    public OptimizationResult optimize(double currentMoisture, double targetMoisture,
55	                                        double temperature, int currentHour, double cropFactor) {
56	        
57	        log.info("开始多目标优化: currentMoisture={}, targetMoisture={}, temp={}, hour={}",
58	                currentMoisture, targetMoisture, temperature, currentHour);
59	
60	        // 1. 初始化种群
61	        List<Individual> population = initializePopulation();
62	
63	        // 2. 进化迭代
64	        for (int gen = 0; gen < MAX_GENERATIONS; gen++) {
65	            // 评估适应度
66	            for (Individual ind : population) {
67	                evaluateFitness(ind, currentMoisture, targetMoisture, temperature, currentHour, cropFactor);
68	            }
69	
70	            // 非支配排序
71	            List<List<Individual>> fronts = fastNonDominatedSort(population);
72	
73	            // 计算拥挤度
74	            for (List<Individual> front : fronts) {
75	                calculateCrowdingDistance(front);
76	            }
77	
78	            // 选择、交叉、变异
79	            List<Individual> offspring = createOffspring(population);
80	
81	            // 合并父代和子代
82	            population.addAll(offspring);
83	
84	            // 再次排序选择
85	            fronts = fastNonDominatedSort(population);
86	            population = selectNewPopulation(fronts, POPULATION_SIZE);
87	        }
88	
89	        // 3. 从帕累托前沿选择最优解
90	        Individual best = selectBestSolution(population, currentMoisture, targetMoisture);
91	
92	        // 4. 构建结果
93	        OptimizationResult result = new OptimizationResult();
94	        result.setWaterAmount(BigDecimal.valueOf(best.waterAmount).setScale(2, RoundingMode.HALF_UP));
95	        result.setDurationSeconds(best.duration);
96	        result.setEstimatedMoistureGain(BigDecimal.valueOf(best.estimatedMoistureGain).setScale(2, RoundingMode.HALF_UP));
97	        result.setPredictedMoisture(BigDecimal.valueOf(currentMoisture + best.estimatedMoistureGain).setScale(2, RoundingMode.HALF_UP));
98	        result.setCost(BigDecimal.valueOf(best.cost).setScale(2, RoundingMode.HALF_UP));
99	        result.setHealthScore(BigDecimal.valueOf(best.healthScore).setScale(2, RoundingMode.HALF_UP));
100	        result.setParetoRank(best.rank);
101	
102	        // 计算综合得分
103	        double totalScore = calculateTotalScore(best);
104	        result.setTotalScore(BigDecimal.valueOf(totalScore).setScale(3, RoundingMode.HALF_UP));
105	
106	        log.info("优化完成: waterAmount={}, duration={}, cost={}, healthScore={}",
107	                result.getWaterAmount(), result.getDurationSeconds(), 
108	                result.getCost(), result.getHealthScore());
109	
110	        return result;
111	    }
112	
113	    /**
114	     * 初始化种群
115	     */
116	    private List<Individual> initializePopulation() {
117	        List<Individual> population = new ArrayList<>();
118	        Random random = new Random();
119	
120	        for (int i = 0; i < POPULATION_SIZE; i++) {
121	            Individual ind = new Individual();
122	            ind.waterAmount = MIN_WATER + random.nextDouble() * (MAX_WATER - MIN_WATER);
123	            ind.duration = MIN_DURATION + random.nextInt(MAX_DURATION - MIN_DURATION);
124	            population.add(ind);
125	        }
126	
127	        return population;
128	    }
129	
130	    /**
131	     * 评估个体适应度（多目标）
132	     */
133	    private void evaluateFitness(Individual ind, double currentMoisture, double targetMoisture,
134	                                  double temperature, int currentHour, double cropFactor) {
135	        
136	        // 目标1：湿度差距（越小越好，转为越大越好）
137	        // 估算湿度提升（简化模型：每升水提升约1.5%）
138	        double moistureGain = ind.waterAmount * 1.5 * cropFactor;
139	        double moistureGap = Math.abs((currentMoisture + moistureGain) - targetMoisture);
140	        ind.estimatedMoistureGain = moistureGain;
141	        ind.moistureScore = Math.max(0, 100 - moistureGap * 2);
142	
143	        // 目标2：用水量（越少越好，转为得分）
144	        ind.waterScore = Math.max(0, 100 - ind.waterAmount * 2);
145	
146	        // 目标3：灌溉成本（考虑峰谷电价）
147	        double priceRate = getPriceRate(currentHour);
148	        ind.cost = ind.waterAmount * 0.01 * priceRate; // 假设每升水成本0.01元*电价系数
149	        ind.costScore = Math.max(0, 100 - ind.cost * 20);
150	
151	        // 目标4：作物健康（基于灌溉时机和量）
152	        // 最佳灌溉量是基于湿度差的合理范围
153	        double idealWater = (targetMoisture - currentMoisture) / 1.5 / cropFactor;
154	        idealWater = Math.max(MIN_WATER, Math.min(MAX_WATER, idealWater));
155	        double waterDeviation = Math.abs(ind.waterAmount - idealWater) / idealWater;
156	        ind.healthScore = Math.max(0, 100 - waterDeviation * 50);
157	
158	        // 温度影响（高温时灌溉效果好但蒸发损失大）
159	        if (temperature > 30) {
160	            ind.healthScore *= 0.9; // 高温时健康分数略降
161	            ind.cost *= 1.1; // 需要更多水
162	        }
163	    }
