177	    /**
178	     * 快速非支配排序（NSGA-II核心）
179	     */
180	    private List<List<Individual>> fastNonDominatedSort(List<Individual> population) {
181	        List<List<Individual>> fronts = new ArrayList<>();
182	        fronts.add(new ArrayList<>());
183	
184	        for (Individual p : population) {
185	            p.dominationCount = 0;
186	            p.dominatedSet = new ArrayList<>();
187	
188	            for (Individual q : population) {
189	                if (dominates(p, q)) {
190	                    p.dominatedSet.add(q);
191	                } else if (dominates(q, p)) {
192	                    p.dominationCount++;
193	                }
194	            }
195	
196	            if (p.dominationCount == 0) {
197	                p.rank = 0;
198	                fronts.get(0).add(p);
199	            }
200	        }
201	
202	        int i = 0;
203	        while (!fronts.get(i).isEmpty()) {
204	            List<Individual> nextFront = new ArrayList<>();
205	            for (Individual p : fronts.get(i)) {
206	                for (Individual q : p.dominatedSet) {
207	                    q.dominationCount--;
208	                    if (q.dominationCount == 0) {
209	                        q.rank = i + 1;
210	                        nextFront.add(q);
211	                    }
212	                }
213	            }
214	            i++;
215	            fronts.add(nextFront);
216	        }
217	
218	        return fronts;
219	    }
