221	    /**
222	     * 判断个体p是否支配个体q
223	     */
224	    private boolean dominates(Individual p, Individual q) {
225	        // 支配条件：所有目标不差于q，且至少有一个目标优于q
226	        boolean atLeastOneBetter = false;
227	
228	        if (p.moistureScore < q.moistureScore) return false;
229	        if (p.moistureScore > q.moistureScore) atLeastOneBetter = true;
230	
231	        if (p.waterScore < q.waterScore) return false;
232	        if (p.waterScore > q.waterScore) atLeastOneBetter = true;
233	
234	        if (p.costScore < q.costScore) return false;
235	        if (p.costScore > q.costScore) atLeastOneBetter = true;
236	
237	        if (p.healthScore < q.healthScore) return false;
238	        if (p.healthScore > q.healthScore) atLeastOneBetter = true;
239	
240	        return atLeastOneBetter;
241	    }
