243	    /**
244	     * 计算拥挤度距离
245	     */
246	    private void calculateCrowdingDistance(List<Individual> front) {
247	        if (front.isEmpty()) return;
248	
249	        int n = front.size();
250	        for (Individual ind : front) {
251	            ind.crowdingDistance = 0;
252	        }
253	
254	        // 对每个目标计算拥挤度
255	        calculateDistanceForObjective(front, Individual::getMoistureScore);
256	        calculateDistanceForObjective(front, Individual::getWaterScore);
257	        calculateDistanceForObjective(front, Individual::getCostScore);
258	        calculateDistanceForObjective(front, Individual::getHealthScore);
259	    }
260	
261	    private void calculateDistanceForObjective(List<Individual> front, 
262	                                                java.util.function.Function<Individual, Double> getter) {
263	        front.sort(Comparator.comparingDouble(getter::apply));
264	        front.get(0).crowdingDistance = Double.POSITIVE_INFINITY;
265	        front.get(front.size() - 1).crowdingDistance = Double.POSITIVE_INFINITY;
266	
267	        double minVal = getter.apply(front.get(0));
268	        double maxVal = getter.apply(front.get(front.size() - 1));
269	        double range = maxVal - minVal;
270	
271	        if (range == 0) return;
272	
273	        for (int i = 1; i < front.size() - 1; i++) {
274	            double distance = (getter.apply(front.get(i + 1)) - getter.apply(front.get(i - 1))) / range;
275	            front.get(i).crowdingDistance += distance;
276	        }
277	    }
