279	    /**
280	     * 创建子代（选择、交叉、变异）
281	     */
282	    private List<Individual> createOffspring(List<Individual> population) {
283	        List<Individual> offspring = new ArrayList<>();
284	        Random random = new Random();
285	
286	        while (offspring.size() < POPULATION_SIZE) {
287	            // 锦标赛选择
288	            Individual parent1 = tournamentSelection(population);
289	            Individual parent2 = tournamentSelection(population);
290	
291	            // 交叉
292	            if (random.nextDouble() < CROSSOVER_RATE) {
293	                Individual child = crossover(parent1, parent2);
294	                offspring.add(child);
295	            } else {
296	                offspring.add(new Individual(parent1));
297	            }
298	        }
299	
300	        // 变异
301	        for (Individual ind : offspring) {
302	            if (random.nextDouble() < MUTATION_RATE) {
303	                mutate(ind);
304	            }
305	        }
306	
307	        return offspring;
308	    }
