310	    /**
311	     * 锦标赛选择
312	     */
313	    private Individual tournamentSelection(List<Individual> population) {
314	        Random random = new Random();
315	        int tournamentSize = 3;
316	        Individual best = null;
317	
318	        for (int i = 0; i < tournamentSize; i++) {
319	            Individual candidate = population.get(random.nextInt(population.size()));
320	            if (best == null || compareIndividuals(candidate, best) > 0) {
321	                best = candidate;
322	            }
323	        }
324	
325	        return best;
326	    }
