328	    /**
329	     * 比较两个个体（用于选择）
330	     */
331	    private int compareIndividuals(Individual a, Individual b) {
332	        // 先比较帕累托等级
333	        if (a.rank != b.rank) {
334	            return Integer.compare(a.rank, b.rank);
335	        }
336	        // 再比较拥挤度
337	        return Double.compare(a.crowdingDistance, b.crowdingDistance);
338	    }
