340	    /**
341	     * 交叉操作
342	     */
343	    private Individual crossover(Individual p1, Individual p2) {
344	        Random random = new Random();
345	        Individual child = new Individual();
346	
347	        // 模拟二进制交叉
348	        double beta = 2 * random.nextDouble() - 1;
349	        child.waterAmount = 0.5 * ((1 + beta) * p1.waterAmount + (1 - beta) * p2.waterAmount);
350	        child.duration = (int) (0.5 * (p1.duration + p2.duration));
351	
352	        // 边界约束
353	        child.waterAmount = Math.max(MIN_WATER, Math.min(MAX_WATER, child.waterAmount));
354	        child.duration = Math.max(MIN_DURATION, Math.min(MAX_DURATION, child.duration));
355	
356	        return child;
357	    }
358	
359	    /**
360	     * 变异操作
361	     */
362	    private void mutate(Individual ind) {
363	        Random random = new Random();
364	
365	        // 多项式变异
366	        double delta = 0.5 * (2 * random.nextDouble() - 1);
367	        ind.waterAmount += delta * 5;
368	        ind.waterAmount = Math.max(MIN_WATER, Math.min(MAX_WATER, ind.waterAmount));
369	
370	        if (random.nextDouble() < 0.5) {
371	            ind.duration += random.nextInt(20) - 10;
372	            ind.duration = Math.max(MIN_DURATION, Math.min(MAX_DURATION, ind.duration));
373	        }
374	    }
