376	    /**
377	     * 选择新一代种群
378	     */
379	    private List<Individual> selectNewPopulation(List<List<Individual>> fronts, int size) {
380	        List<Individual> newPopulation = new ArrayList<>();
381	
382	        for (List<Individual> front : fronts) {
383	            if (newPopulation.size() + front.size() <= size) {
384	                newPopulation.addAll(front);
385	            } else {
386	                // 按拥挤度排序
387	                front.sort((a, b) -> Double.compare(b.crowdingDistance, a.crowdingDistance));
388	                int remaining = size - newPopulation.size();
389	                newPopulation.addAll(front.subList(0, remaining));
390	                break;
391	            }
392	        }
393	
394	        return newPopulation;
395	    }
