397	    /**
398	     * 从帕累托前沿选择最优解
399	     */
400	    private Individual selectBestSolution(List<Individual> population, 
401	                                           double currentMoisture, double targetMoisture) {
402	        // 找到帕累托前沿（rank=0的个体）
403	        List<Individual> paretoFront = population.stream()
404	                .filter(ind -> ind.rank == 0)
405	                .collect(Collectors.toList());
406	
407	        if (paretoFront.isEmpty()) {
408	            paretoFront = population;
409	        }
410	
411	        // 根据综合得分选择
412	        return paretoFront.stream()
413	                .max(Comparator.comparingDouble(this::calculateTotalScore))
414	                .orElse(paretoFront.get(0));
415	    }
