417	    /**
418	     * 计算综合得分
419	     */
420	    private double calculateTotalScore(Individual ind) {
421	        // 加权综合（可根据实际需求调整权重）
422	        double w1 = 0.35; // 湿度达标权重
423	        double w2 = 0.25; // 节水权重
424	        double w3 = 0.20; // 成本权重
425	        double w4 = 0.20; // 健康权重
426	
427	        return w1 * ind.moistureScore + w2 * ind.waterScore + 
428	               w3 * ind.costScore + w4 * ind.healthScore;
429	    }
