39	    // 基础参数
40	    private static final BigDecimal WATER_PER_SECOND = new BigDecimal("0.5");
41	    private static final BigDecimal DEFAULT_MOISTURE_GAIN = new BigDecimal("1.6667");
42	    private static final int MIN_DURATION_SEC = 10;
43	    private static final int MAX_DURATION_SEC = 180;
