45	    /**
46	     * 构建智能灌溉计划
47	     */
48	    public SmartIrrigationPlanDTO buildSmartPlan(Long pointId, EnvironmentDataDTO envData,
49	                                                   IrrigationPlanConfig config) {
50	        SmartIrrigationPlanDTO plan = new SmartIrrigationPlanDTO();
51	
52	        // 1. 检查基础数据
53	        if (envData == null || envData.getSoilMoisture() == null) {
54	            plan.setShouldIrrigate(false);
55	            plan.setDecisionType("standard");
56	            plan.setReason("缺少环境数据");
57	            return plan;
58	        }
59	
60	        // 2. 获取阈值配置
61	        int threshold = getThreshold(config);
62	        BigDecimal soilMoisture = envData.getSoilMoisture();
63	
64	        plan.setCurrentMoisture(soilMoisture);
65	        plan.setPredictionMode("ewma");
66	
67	        // 3. 获取作物生长阶段策略
68	        IrrigationStrategyDTO strategy = cropStageService.getStrategy(pointId);
69	        plan.setCropStage(strategy.getCurrentStage());
70	        plan.setIrrigationFactor(strategy.getIrrigationFactor());
71	
72	        // 4. 执行预测分析
73	        MoisturePredictionDTO prediction = moisturePredictor.analyze(pointId, threshold);
74	        plan.setPredictedMoisture(prediction.getPredict2h());
75	        plan.setConfidence(prediction.getConfidence());
76	
77	        // 5. 决策逻辑
78	        if (soilMoisture.compareTo(BigDecimal.valueOf(threshold)) < 0) {
79	            plan.setShouldIrrigate(true);
80	            plan.setDecisionType("adaptive");
81	            plan.setReason("当前湿度低于阈值，需要立即灌溉");
82	        } else if (Boolean.TRUE.equals(prediction.getNeedPreIrrigation())) {
83	            plan.setShouldIrrigate(true);
84	            plan.setDecisionType("predictive");
85	            plan.setReason(prediction.getReason());
86	        } else {
87	            plan.setShouldIrrigate(false);
88	            plan.setDecisionType(strategy.getHasCropConfig() ? "stage_based" : "standard");
89	            plan.setReason(prediction.getReason());
90	            return plan;
91	        }
92	
93	        // 6. 计算用水量
94	        BigDecimal targetMoisture = calculateTargetMoisture(threshold, strategy);
95	        BigDecimal moistureGap = targetMoisture.subtract(soilMoisture).max(BigDecimal.ZERO);
96	
97	        BigDecimal baseWaterAmount = moistureGap.divide(DEFAULT_MOISTURE_GAIN, 4, RoundingMode.HALF_UP);
98	
99	        BigDecimal riskFactor = calculateRiskFactor(envData);
100	        BigDecimal waterAmount = baseWaterAmount.multiply(riskFactor);
101	
102	        waterAmount = cropStageService.adjustWaterByStage(waterAmount, strategy, soilMoisture);
103	        waterAmount = learningService.adjustWaterAmount(pointId, waterAmount);
104	        waterAmount = clamp(waterAmount, new BigDecimal("0.5"), new BigDecimal("45"));
105	
106	        // 7. 计算灌溉时长
107	        int durationSeconds = waterAmount.divide(WATER_PER_SECOND, 0, RoundingMode.HALF_UP).intValue();
108	        durationSeconds = Math.max(MIN_DURATION_SEC, Math.min(MAX_DURATION_SEC, durationSeconds));
109	
110	        // 8. 设置计划
111	        plan.setWaterAmountL(waterAmount.setScale(1, RoundingMode.HALF_UP));
112	        plan.setDurationSeconds(durationSeconds);
113	        plan.setTargetMoisture(targetMoisture.setScale(1, RoundingMode.HALF_UP));
114	
115	        log.info("智能灌溉计划: pointId={}, shouldIrrigate={}, decisionType={}, water={}, duration={}",
116	                pointId, plan.getShouldIrrigate(), plan.getDecisionType(),
117	                plan.getWaterAmountL(), plan.getDurationSeconds());
118	
119	        return plan;
120	    }
