22	 */
23	@RestController
24	@RequestMapping("/ai")
25	@RequiredArgsConstructor
26	@Tag(name = "AI助手", description = "智慧农业AI对话接口")
27	public class AiTestController {
28	
29	    private final Assistant assistant;
30	    private final ChatMemoryStore chatMemoryStore;
31	    private final ChatHistoryService chatHistoryService;
