33	    /**
34	     * 同步对话（POST，供前端调用）
35	     * @param request 请求体 {sessionId, message, context}
36	     * @return JSON 响应 {code, message, data: {reply, sessionId}}
37	     */
38	    @Operation(summary = "AI对话(同步)", description = "POST方式调用，返回完整JSON响应")
39	    @PostMapping(value = "/chat", produces = MediaType.APPLICATION_JSON_VALUE)
40	    public ResponseEntity<Map<String, Object>> chatSync(@RequestBody Map<String, String> request) {
41	        String sessionId = request.getOrDefault("sessionId", "");
42	        String message = request.getOrDefault("message", "你好");
43	        String context = request.getOrDefault("context", "");
44	
45	        // 如果有上下文信息，附加到消息中
46	        String fullMessage = context.isEmpty() ? message : context + "\n\n用户问题：" + message;
47	
48	        String reply;
49	        if (sessionId != null && !sessionId.isBlank()) {
50	            // 带记忆的对话
51	            chatHistoryService.saveUserMessage(sessionId, message);
52	            reply = assistant.chatSync(sessionId, fullMessage);
53	            chatHistoryService.saveAssistantMessage(sessionId, reply);
54	        } else {
55	            // 无记忆的一次性对话
56	            sessionId = "session_" + System.currentTimeMillis();
57	            reply = assistant.chatSync(sessionId, fullMessage);
58	        }
59	
60	        Map<String, Object> data = new HashMap<>();
61	        data.put("reply", reply);
62	        data.put("sessionId", sessionId);
63	
64	        Map<String, Object> response = new HashMap<>();
65	        response.put("code", 200);
66	        response.put("message", "success");
67	        response.put("data", data);
68	
69	        return ResponseEntity.ok(response);
70	    }
