78	    @Operation(summary = "AI对话(流式)", description = "支持流式响应，传入sessionId启用对话记忆")
79	    @GetMapping(value = "/chat/stream", produces = MediaType.TEXT_EVENT_STREAM_VALUE)
80	    public Flux<String> chatStream(
