1	package com.agriculture.ai;
2	
3	import dev.langchain4j.data.message.ChatMessage;
4	import dev.langchain4j.memory.chat.ChatMemoryProvider;
5	import dev.langchain4j.memory.chat.MessageWindowChatMemory;
6	import dev.langchain4j.model.chat.listener.ChatModelErrorContext;
7	import dev.langchain4j.model.chat.listener.ChatModelListener;
8	import dev.langchain4j.model.chat.listener.ChatModelRequestContext;
9	import dev.langchain4j.model.chat.listener.ChatModelResponseContext;
10	import dev.langchain4j.store.memory.chat.ChatMemoryStore;
11	import lombok.RequiredArgsConstructor;
12	import lombok.extern.slf4j.Slf4j;
13	import org.slf4j.Logger;
14	import org.slf4j.LoggerFactory;
15	import org.springframework.context.annotation.Bean;
16	import org.springframework.context.annotation.Configuration;
17	import org.springframework.data.redis.core.RedisTemplate;
18	
19	import java.time.Duration;
20	import java.util.List;
21	
22	import static dev.langchain4j.data.message.ChatMessageDeserializer.messagesFromJson;
23	import static dev.langchain4j.data.message.ChatMessageSerializer.messagesToJson;
24	
25	@Slf4j
26	@Configuration
27	public class AiConfiguration {
28	
29	    @Bean
30	    ChatModelListener chatModelListener() {
31	        return new ChatModelListener() {
32	            private static final Logger log = LoggerFactory.getLogger(ChatModelListener.class);
33	            @Override
34	            public void onRequest(ChatModelRequestContext requestContext) {
35	                log.info("onRequest(): {}", requestContext.chatRequest());
36	            }
37	            @Override
38	            public void onResponse(ChatModelResponseContext responseContext) {
39	                log.info("onResponse(): {}", responseContext.chatResponse());
40	            }
41	
42	            @Override
43	            public void onError(ChatModelErrorContext errorContext) {
44	                log.info("onError(): {}", errorContext.error().getMessage());
45	            }
46	        };
47	    }
48	
49	    /**
50	     * Redis 存储实现
51	     * 会话记忆持久化到 Redis，支持分布式部署
52	     */
53	    @Bean
54	    ChatMemoryStore chatMemoryStore(RedisTemplate<String, String> redisTemplate) {
55	        return new RedisChatMemoryStore(redisTemplate);
56	    }
57	
58	    /**
59	     * 记忆提供者：按会话ID创建独立的滑动窗口记忆
60	     * 每个会话保留最近 10 条消息
61	     */
62	    @Bean
63	    ChatMemoryProvider chatMemoryProvider(ChatMemoryStore chatMemoryStore) {
64	        return memoryId -> MessageWindowChatMemory.builder()
65	                .id(memoryId)
66	                .maxMessages(10)
67	                .chatMemoryStore(chatMemoryStore)
68	                .build();
69	    }
70	
71	    /**
72	     * 基于 Redis 的对话记忆存储
73	     */
74	    @RequiredArgsConstructor
75	    static class RedisChatMemoryStore implements ChatMemoryStore {
76	
77	        private static final String KEY_PREFIX = "ai:chat:memory:";
78	        private static final Duration TTL = Duration.ofHours(24);
79	
80	        private final RedisTemplate<String, String> redisTemplate;
81	
82	        @Override
83	        public List<ChatMessage> getMessages(Object memoryId) {
84	            String json = redisTemplate.opsForValue().get(key(memoryId));
85	            if (json == null || json.isEmpty()) {
86	                return List.of();
87	            }
88	            return messagesFromJson(json);
89	        }
90	
91	        @Override
92	        public void updateMessages(Object memoryId, List<ChatMessage> messages) {
93	            String json = messagesToJson(messages);
94	            redisTemplate.opsForValue().set(key(memoryId), json, TTL);
95	        }
96	
97	        @Override
98	        public void deleteMessages(Object memoryId) {
99	            redisTemplate.delete(key(memoryId));
100	        }
101	
102	        private String key(Object memoryId) {
103	            return KEY_PREFIX + memoryId;
104	        }
105	    }
106	}
