1	package com.agriculture.ai.tools;
2	
3	import com.agriculture.model.dto.EnvironmentDataDTO;
4	import com.agriculture.service.SensorDataService;
5	import dev.langchain4j.agent.tool.Tool;
6	import lombok.RequiredArgsConstructor;
7	import lombok.extern.slf4j.Slf4j;
8	import org.springframework.stereotype.Component;
9	
10	import java.util.List;
11	
12	/**
13	 * 环境数据查询工具类
14	 * 为 AI 助手提供传感器数据和环境监测能力
15	 */
16	@Slf4j
17	@Component
18	@RequiredArgsConstructor
19	public class EnvironmentTools {
20	
21	    private final SensorDataService sensorDataService;
22	
23	    @Tool("获取指定检测点的当前环境数据，包括温度、湿度、光照、CO2浓度、土壤湿度等")
24	    public EnvironmentDataDTO getCurrentEnvironment(Long pointId) {
25	        log.info("[AI Tool] 获取检测点 {} 的当前环境数据", pointId);
26	        return sensorDataService.getCurrentData(pointId);
27	    }
28	
29	    @Tool("获取指定检测点的历史环境数据，limit参数指定返回记录数量，最多100条")
30	    public List<EnvironmentDataDTO> getHistoryEnvironment(Long pointId, Integer limit) {
31	        int actualLimit = limit != null ? Math.min(limit, 100) : 10;
32	        log.info("[AI Tool] 获取检测点 {} 的历史环境数据，数量: {}", pointId, actualLimit);
33	        return sensorDataService.getHistoryData(pointId, actualLimit);
34	    }
35	
36	    @Tool("分析当前环境状况并返回简要报告，包括温度、湿度、光照、土壤湿度是否正常")
37	    public String analyzeEnvironmentStatus(Long pointId) {
38	        log.info("[AI Tool] 分析检测点 {} 的环境状况", pointId);
39	        
40	        EnvironmentDataDTO data = sensorDataService.getCurrentData(pointId);
41	        if (data == null) {
42	            return "无法获取检测点 " + pointId + " 的环境数据";
43	        }
44	
45	        StringBuilder report = new StringBuilder();
46	        report.append("【检测点 ").append(pointId).append(" 环境分析报告】\n");
47	        
48	        // 温度分析
49	        if (data.getTemperature() != null) {
50	            double temp = data.getTemperature().doubleValue();
51	            report.append("温度: ").append(temp).append("°C - ");
52	            if (temp < 10) {
53	                report.append("⚠️ 过低，建议采取保温措施\n");
54	            } else if (temp > 35) {
55	                report.append("⚠️ 过高，建议通风降温\n");
56	            } else {
57	                report.append("✅ 正常\n");
58	            }
59	        }
60	
61	        // 湿度分析
62	        if (data.getHumidity() != null) {
63	            double humidity = data.getHumidity().doubleValue();
64	            report.append("湿度: ").append(humidity).append("% - ");
65	            if (humidity < 30) {
66	                report.append("⚠️ 过低，空气干燥\n");
67	            } else if (humidity > 80) {
68	                report.append("⚠️ 过高，注意通风除湿\n");
69	            } else {
70	                report.append("✅ 正常\n");
71	            }
72	        }
73	
74	        // 光照分析
75	        if (data.getLight() != null) {
76	            double light = data.getLight().doubleValue();
77	            report.append("光照: ").append(light).append(" lux - ");
78	            if (light < 300) {
79	                report.append("⚠️ 光照不足\n");
80	            } else {
81	                report.append("✅ 正常\n");
82	            }
83	        }
84	
85	        // CO2分析
86	        if (data.getCo2() != null) {
87	            double co2 = data.getCo2().doubleValue();
88	            report.append("CO2: ").append(co2).append(" ppm - ");
89	            if (co2 > 1000) {
90	                report.append("⚠️ 浓度过高，建议通风\n");
91	            } else {
92	                report.append("✅ 正常\n");
93	            }
94	        }
95	
96	        // 土壤湿度分析
97	        if (data.getSoilMoisture() != null) {
98	            double soilMoisture = data.getSoilMoisture().doubleValue();
99	            report.append("土壤湿度: ").append(soilMoisture).append("% - ");
100	            if (soilMoisture < 40) {
101	                report.append("⚠️ 土壤干燥，建议灌溉\n");
102	            } else {
103	                report.append("✅ 正常\n");
104	            }
105	        }
106	
107	        return report.toString();
108	    }
109	}
