13	
14	import java.util.List;
15	
16	/**
17	 * 灌溉控制工具类
18	 * 为 AI 助手提供灌溉控制和查询能力
19	 */
20	@Slf4j
21	@Component
22	@RequiredArgsConstructor
23	public class IrrigationTools {
24	
25	    private final IrrigationService irrigationService;
26	    private final SensorDataService sensorDataService;
27	
28	    @Tool("开始灌溉操作。pointId为检测点ID，duration为灌溉时长（秒），mode为模式（0-自动，1-手动）")
29	    public IrrigationDTO startIrrigation(Long pointId, Integer duration, Integer mode) {
30	        log.info("[AI Tool] 开始灌溉: 检测点={}, 时长={}秒, 模式={}", pointId, duration, mode);
31	        
32	        IrrigationDTO.StartRequest request = new IrrigationDTO.StartRequest();
33	        request.setPointId(pointId);
34	        request.setDuration(duration != null ? duration : 60);
35	        request.setMode(mode != null ? mode : 1);
36	        
37	        return irrigationService.startIrrigation(request);
38	    }
39	
40	    @Tool("停止正在进行的灌溉任务。logId为灌溉记录ID")
41	    public IrrigationDTO stopIrrigation(Long logId) {
42	        log.info("[AI Tool] 停止灌溉: 记录ID={}", logId);
43	        return irrigationService.stopIrrigation(logId);
44	    }
45	
46	    @Tool("获取指定检测点的灌溉历史记录")
47	    public List<IrrigationDTO> getIrrigationHistory(Long pointId) {
48	        log.info("[AI Tool] 获取检测点 {} 的灌溉历史", pointId);
49	        return irrigationService.getLogsByPointId(pointId);
50	    }
51	
52	    @Tool("获取指定检测点最近一次灌溉记录")
53	    public IrrigationDTO getLatestIrrigation(Long pointId) {
54	        log.info("[AI Tool] 获取检测点 {} 最近灌溉记录", pointId);
55	        return irrigationService.getLatestLog(pointId);
56	    }
57	
58	    @Tool("获取指定检测点的总灌溉用水量（升）")
59	    public Double getTotalWaterAmount(Long pointId) {
60	        log.info("[AI Tool] 获取检测点 {} 总用水量", pointId);
61	        return irrigationService.getTotalWaterAmount(pointId);
62	    }
63	
64	    @Tool("根据当前环境数据生成智能灌溉计划建议，返回建议的灌溉时长和用水量")
65	    public AutoIrrigationPlanResponse getIrrigationPlan(Long pointId) {
66	        log.info("[AI Tool] 生成检测点 {} 的智能灌溉计划", pointId);
67	        
68	        EnvironmentDataDTO envData = sensorDataService.getCurrentData(pointId);
69	        
70	        IrrigationPlanRequest request = new IrrigationPlanRequest();
71	        request.setPointId(pointId);
72	        request.setEnvData(envData);
73	        
74	        return irrigationService.buildAutoPlan(request);
75	    }
76	
77	    @Tool("检查当前环境是否需要灌溉，并返回灌溉建议")
78	    public String checkIrrigationNeed(Long pointId) {
79	        log.info("[AI Tool] 检查检测点 {} 是否需要灌溉", pointId);
80	        
81	        EnvironmentDataDTO envData = sensorDataService.getCurrentData(pointId);
82	        if (envData == null) {
83	            return "无法获取检测点 " + pointId + " 的环境数据";
84	        }
85	
86	        IrrigationPlanRequest request = new IrrigationPlanRequest();
87	        request.setPointId(pointId);
88	        request.setEnvData(envData);
