8	
9	/**
10	 * 跨域配置
11	 */
12	@Configuration
13	public class CorsConfig {
14	
15	    @Bean
16	    public CorsFilter corsFilter() {
17	        CorsConfiguration config = new CorsConfiguration();
18	
19	        // 允许所有来源
20	        config.addAllowedOriginPattern("*");
21	
22	        // 允许所有请求头
23	        config.addAllowedHeader("*");
24	
25	        // 允许所有请求方法
26	        config.addAllowedMethod("*");
27	
28	        // 允许携带凭证
29	        config.setAllowCredentials(true);
30	
31	        // 预检请求缓存时间
32	        config.setMaxAge(3600L);
33	
34	        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
35	        source.registerCorsConfiguration("/**", config);
36	
37	        return new CorsFilter(source);
38	    }
39	}
