36	     */
37	    @ExceptionHandler(RuntimeException.class)
38	    @ResponseStatus(HttpStatus.INTERNAL_SERVER_ERROR)
39	    public ApiResponse<Void> handleRuntimeException(RuntimeException e) {
40	        log.error("运行时异常: ", e);
41	        return ApiResponse.error(e.getMessage());
42	    }
43	
44	    /**
45	     * 其他异常
46	     */
47	    @ExceptionHandler(Exception.class)
