50	                .map(this::toDTO)
51	                .collect(Collectors.toList());
52	    }
53	
54	    public Page<AlarmDTO> getUnprocessedAlarmsPaged(int pageNum, int pageSize) {
55	        Page<Alarm> page = new Page<>(pageNum + 1, pageSize);
56	        LambdaQueryWrapper<Alarm> wrapper = new LambdaQueryWrapper<>();
57	        wrapper.eq(Alarm::getStatus, 0)
58	                .orderByDesc(Alarm::getCreatedAt);
59	        Page<Alarm> alarmPage = alarmMapper.selectPage(page, wrapper);
60	
61	        Page<AlarmDTO> dtoPage = new Page<>(pageNum + 1, pageSize);
