73	    }
74	
75	
76	    public AlarmDTO getAlarmById(Long id) {
77	        Alarm alarm = alarmMapper.selectById(id);
78	        return alarm != null ? toDTO(alarm) : null;
79	    }
80	
81	    @Transactional
82	    public AlarmDTO handleAlarm(Long id, String remark) {
83	        Alarm alarm = alarmMapper.selectById(id);
84	        if (alarm == null) {
85	            throw new RuntimeException("报警记录不存在: " + id);
86	        }
87	
88	        if (alarm.getStatus() == 1) {
89	            throw new RuntimeException("报警已处理");
90	        }
91	
92	        alarm.setStatus(1);
93	        alarm.setHandledAt(LocalDateTime.now());
94	
95	        alarmMapper.updateById(alarm);
96	        log.info("处理报警: ID={}, 类型={}", id, alarm.getAlarmType());
97	
98	        return toDTO(alarm);
99	    }
100	
101	    @Transactional
102	    public void handleAllByPointId(Long pointId) {
103	        LocalDateTime now = LocalDateTime.now();
104	        int affected = alarmMapper.handleAllByPointId(pointId, now);
105	        log.info("处理检测点{}的所有未处理报警, 共{}条", pointId, affected);
106	    }
107	
108	    @Transactional
109	    public void deleteAlarm(Long id) {
110	        alarmMapper.deleteById(id);
111	    }
112	
113	    private AlarmDTO toDTO(Alarm alarm) {
114	        AlarmDTO dto = new AlarmDTO();
115	        dto.setId(alarm.getId());
116	        dto.setPointId(alarm.getPointId());
117	        dto.setAlarmType(alarm.getAlarmType());
118	        dto.setAlarmValue(alarm.getAlarmValue());
119	        dto.setThreshold(alarm.getThreshold());
120	        dto.setStatus(alarm.getStatus());
121	        dto.setCreatedAt(alarm.getCreatedAt());
122	        dto.setHandledAt(alarm.getHandledAt());
123	        return dto;
124	    }
125	}
