1	package com.agriculture.service;
2	
3	import com.agriculture.model.dto.WeatherDTO;
4	import com.fasterxml.jackson.databind.JsonNode;
5	import com.fasterxml.jackson.databind.ObjectMapper;
6	import lombok.extern.slf4j.Slf4j;
7	import org.springframework.beans.factory.annotation.Value;
8	import org.springframework.cache.annotation.Cacheable;
9	import org.springframework.stereotype.Service;
10	import org.springframework.web.client.RestTemplate;
11	import org.springframework.web.util.UriComponentsBuilder;
12	
13	import java.time.LocalDate;
14	import java.time.format.DateTimeFormatter;
15	import java.util.ArrayList;
16	import java.util.List;
17	
18	/**
19	 * 天气服务
20	 * 使用和风天气API获取天气数据
21	 */
22	@Service
23	@Slf4j
24	public class WeatherService {
25	
26	    @Value("${weather.qweather.api-key:}")
27	    private String apiKey;
28	
29	    @Value("${weather.qweather.api-host:devapi.qweather.com}")
30	    private String apiHost;
31	
32	    @Value("${weather.qweather.geo-host:geoapi.qweather.com}")
33	    private String geoApiHost;
34	
35	    private final RestTemplate restTemplate = new RestTemplate();
36	    private final ObjectMapper objectMapper = new ObjectMapper();
37	
38	    /**
39	     * 根据经纬度获取天气
40	     * @param latitude 纬度
41	     * @param longitude 经度
42	     */
43	    @Cacheable(value = "weather", key = "#latitude.toString() + '_' + #longitude.toString()", unless = "#result == null")
44	    public WeatherDTO getWeatherByLocation(Double latitude, Double longitude) {
45	        checkApiKey();
46	        
47	        try {
48	            // 1. 先根据经纬度查询城市信息
49	            String locationId = getLocationIdByCoords(latitude, longitude);
50	            if (locationId == null) {
51	                throw new RuntimeException("无法识别该位置");
52	            }
53	            
54	            log.info("位置查询成功: 经纬度 ({}, {}) -> 城市ID {}", latitude, longitude, locationId);
55	            
56	            // 2. 根据城市ID获取天气
57	            return fetchWeatherByLocationId(locationId, latitude, longitude);
58	        } catch (Exception e) {
59	            log.error("获取天气失败", e);
60	            throw new RuntimeException("获取天气失败: " + e.getMessage());
61	        }
62	    }
63	
64	    /**
65	     * 检查API Key是否配置
66	     */
67	    private void checkApiKey() {
68	        if (apiKey == null || apiKey.isEmpty()) {
69	            throw new RuntimeException("天气服务未配置API Key，请联系管理员配置和风天气API");
70	        }
71	    }
72	
73	    /**
74	     * 根据经纬度获取城市ID
75	     */
76	    private String getLocationIdByCoords(Double latitude, Double longitude) {
77	        try {
78	            // 和风天气 GeoAPI - 根据经纬度查询城市
79	            // location参数格式: 经度,纬度
80	            String location = String.format("%.2f,%.2f", longitude, latitude);
81	            
82	            String url = UriComponentsBuilder.newInstance()
83	                    .scheme("https")
84	                    .path("geo/v2/city/lookup")
85	                    .queryParam("location", location)
86	                    .queryParam("key", apiKey)
87	                    .build()
88	                    .toUriString();
89	
90	            log.info("请求城市查询: {}", url);
91	            String response = restTemplate.getForObject(url, String.class);
92	            JsonNode root = objectMapper.readTree(response);
93	            
94	            String code = root.path("code").asText();
95	            if (!"200".equals(code)) {
96	                log.error("城市查询失败: code={}", code);
97	                return null;
98	            }
99	
100	            JsonNode locationNode = root.path("location");
101	            if (locationNode.isArray() && locationNode.size() > 0) {
102	                JsonNode first = locationNode.get(0);
103	                return first.path("id").asText();
104	            }
105	            
106	            return null;
107	        } catch (Exception e) {
108	            log.error("城市查询请求失败", e);
109	            return null;
110	        }
111	    }
112	
113	    /**
114	     * 根据城市ID获取天气
115	     */
116	    private WeatherDTO fetchWeatherByLocationId(String locationId, Double latitude, Double longitude) {
117	        try {
118	            // 获取当前天气
119	            String nowUrl = UriComponentsBuilder.newInstance()
120	                    .scheme("https")
121	                    .host(apiHost)
122	                    .path("/v7/weather/now")
123	                    .queryParam("location", locationId)
124	                    .queryParam("key", apiKey)
125	                    .build()
126	                    .toUriString();
127	
128	            String nowResponse = restTemplate.getForObject(nowUrl, String.class);
129	            JsonNode nowRoot = objectMapper.readTree(nowResponse);
130	            String code = nowRoot.path("code").asText();
131	
132	            if (!"200".equals(code)) {
133	                log.error("天气API返回错误: {}", code);
134	                throw new RuntimeException("天气API错误: " + code);
135	            }
136	
137	            JsonNode now = nowRoot.path("now");
138	            WeatherDTO weather = new WeatherDTO();
139	            weather.setTemp(parseDouble(now.path("temp").asText()));
140	            weather.setFeelsLike(parseDouble(now.path("feelsLike").asText()));
141	            weather.setText(now.path("text").asText());
142	            weather.setIcon(now.path("icon").asText());
143	            weather.setHumidity(parseInt(now.path("humidity").asText()));
144	            weather.setWindDir(now.path("windDir").asText());
145	            weather.setWindSpeed(parseDouble(now.path("windSpeed").asText()));
146	            weather.setPressure(parseInt(now.path("pressure").asText()));
147	            weather.setVisibility(parseDouble(now.path("vis").asText()));
148	            weather.setUpdateTime(now.path("obsTime").asText());
149	            
150	            // 设置位置信息
151	            weather.setLocationId(locationId);
152	            weather.setLatitude(latitude);
153	            weather.setLongitude(longitude);
154	
155	            // 获取城市名称
156	            LocationInfo locInfo = getCityName(locationId);
157	            if (locInfo != null) {
158	                weather.setLocation(locInfo.getName());
159	                weather.setCity(locInfo.getCity());
160	                weather.setProvince(locInfo.getProvince());
161	            }
162	
163	            // 获取天气预报
164	            weather.setForecast(fetchForecast(locationId));
165	
166	            return weather;
167	        } catch (Exception e) {
168	            log.error("获取天气数据失败", e);
169	            throw new RuntimeException("获取天气数据失败: " + e.getMessage());
170	        }
171	    }
172	
173	    /**
174	     * 获取城市名称
175	     */
176	    private LocationInfo getCityName(String locationId) {
177	        try {
178	            String url = UriComponentsBuilder.newInstance()
179	                    .scheme("https")
180	                    .host(geoApiHost)
181	                    .path("/v2/city/lookup")
182	                    .queryParam("location", locationId)
183	                    .queryParam("key", apiKey)
184	                    .build()
185	                    .toUriString();
186	
187	            String response = restTemplate.getForObject(url, String.class);
188	            JsonNode root = objectMapper.readTree(response);
189	
190	            if ("200".equals(root.path("code").asText())) {
191	                JsonNode locationNode = root.path("location");
192	                if (locationNode.isArray() && locationNode.size() > 0) {
193	                    JsonNode first = locationNode.get(0);
194	                    LocationInfo info = new LocationInfo();
195	                    info.setName(first.path("name").asText());
196	                    info.setCity(first.path("name").asText());
197	                    info.setProvince(first.path("adm1").asText());
198	                    return info;
199	                }
200	            }
201	        } catch (Exception e) {
202	            log.warn("获取城市名称失败", e);
203	        }
204	        return null;
205	    }
206	
207	    /**
208	     * 获取天气预报
209	     */
210	    private List<WeatherDTO.ForecastDTO> fetchForecast(String locationId) {
211	        try {
212	            String forecastUrl = UriComponentsBuilder.newInstance()
213	                    .scheme("https")
214	                    .host(apiHost)
215	                    .path("/v7/weather/3d")
216	                    .queryParam("location", locationId)
217	                    .queryParam("key", apiKey)
218	                    .build()
219	                    .toUriString();
220	
221	            String response = restTemplate.getForObject(forecastUrl, String.class);
222	            JsonNode root = objectMapper.readTree(response);
223	
224	            if (!"200".equals(root.path("code").asText())) {
225	                return new ArrayList<>();
226	            }
227	
228	            List<WeatherDTO.ForecastDTO> forecast = new ArrayList<>();
229	            JsonNode daily = root.path("daily");
230	            for (int i = 0; i < Math.min(3, daily.size()); i++) {
231	                JsonNode day = daily.get(i);
232	                WeatherDTO.ForecastDTO dto = new WeatherDTO.ForecastDTO();
233	                dto.setDate(formatDate(day.path("fxDate").asText()));
234	                dto.setTempMax(parseInt(day.path("tempMax").asText()));
235	                dto.setTempMin(parseInt(day.path("tempMin").asText()));
236	                dto.setTextDay(day.path("textDay").asText());
237	                dto.setTextNight(day.path("textNight").asText());
238	                dto.setIconDay(day.path("iconDay").asText());
239	                dto.setIconNight(day.path("iconNight").asText());
240	                forecast.add(dto);
241	            }
242	            return forecast;
243	        } catch (Exception e) {
244	            log.warn("获取天气预报失败", e);
245	            return new ArrayList<>();
246	        }
247	    }
248	
249	    private Double parseDouble(String value) {
250	        try {
251	            return Double.parseDouble(value);
252	        } catch (Exception e) {
253	            return 0.0;
254	        }
255	    }
256	
257	    private Integer parseInt(String value) {
258	        try {
259	            return Integer.parseInt(value);
260	        } catch (Exception e) {
261	            return 0;
262	        }
263	    }
264	
265	    private String formatDate(String date) {
266	        try {
267	            LocalDate d = LocalDate.parse(date);
268	            return d.format(DateTimeFormatter.ofPattern("MM-dd"));
269	        } catch (Exception e) {
270	            return date;
271	        }
272	    }
273	
274	    /**
275	     * 位置信息内部类
276	     */
277	    private static class LocationInfo {
278	        private String name;
279	        private String city;
280	        private String province;
281	
282	        public String getName() { return name; }
283	        public void setName(String name) { this.name = name; }
284	        public String getCity() { return city; }
285	        public void setCity(String city) { this.city = city; }
286	        public String getProvince() { return province; }
287	        public void setProvince(String province) { this.province = province; }
288	    }
289	}
