7	import lombok.RequiredArgsConstructor;
8	import lombok.extern.slf4j.Slf4j;
9	import org.springframework.scheduling.annotation.Async;
10	import org.springframework.stereotype.Service;
11	
12	import java.util.List;
13	
14	@Slf4j
15	@Service
16	@RequiredArgsConstructor
17	public class ChatHistoryService {
18	
19	    private final AiInteractionMapper aiInteractionMapper;
20	    private static final String TYPE_CHAT = "chat";
21	
22	    /**
23	     * 保存用户消息
24	     */
25	    public void saveUserMessage(String sessionId, String content) {
26	        saveMessage(sessionId, "user", content);
27	    }
28	
29	    /**
30	     * 保存助手消息
31	     */
32	    public void saveAssistantMessage(String sessionId, String content) {
33	        saveMessage(sessionId, "assistant", content);
34	    }
35	
36	    /**
37	     * 异步保存消息（不阻塞流式响应）
38	     */
39	    @Async
40	    public void saveMessageAsync(String sessionId, String role, String content) {
41	        saveMessage(sessionId, role, content);
42	    }
43	
44	    /**
45	     * 保存消息
46	     */
47	    private void saveMessage(String sessionId, String role, String content) {
48	        AiInteraction history = new AiInteraction();
49	        history.setSessionId(sessionId);
50	        history.setRole(role);
51	        history.setContent(content);
52	        history.setInteractionType(TYPE_CHAT);
53	        aiInteractionMapper.insert(history);
54	        log.debug("保存对话历史: sessionId={}, role={}", sessionId, role);
55	    }
56	
57	    /**
58	     * 获取会话的完整历史
59	     */
60	    public List<AiInteraction> getHistoryBySessionId(String sessionId) {
61	        return aiInteractionMapper.findBySessionId(sessionId);
62	    }
63	
64	    /**
65	     * 分页获取会话历史
66	     */
67	    public Page<AiInteraction> getHistoryPaged(String sessionId, int pageNum, int pageSize) {
68	        Page<AiInteraction> page = new Page<>(pageNum + 1, pageSize);
69	        LambdaQueryWrapper<AiInteraction> wrapper = new LambdaQueryWrapper<>();
70	        wrapper.eq(AiInteraction::getSessionId, sessionId)
71	                .eq(AiInteraction::getInteractionType, TYPE_CHAT)
72	                .orderByAsc(AiInteraction::getCreatedAt);
73	        return aiInteractionMapper.selectPage(page, wrapper);
74	    }
75	
76	    /**
77	     * 获取最近N条历史
78	     */
79	    public List<AiInteraction> getRecentHistory(String sessionId, int limit) {
80	        LambdaQueryWrapper<AiInteraction> wrapper = new LambdaQueryWrapper<>();
81	        wrapper.eq(AiInteraction::getSessionId, sessionId)
82	                .eq(AiInteraction::getInteractionType, TYPE_CHAT)
83	                .orderByDesc(AiInteraction::getCreatedAt)
84	                .last("LIMIT " + limit);
85	        return aiInteractionMapper.selectList(wrapper);
86	    }
87	
