19	/**
20	 * 作物生长阶段服务
21	 * 根据作物生长周期动态调整灌溉策略
22	 */
23	@Slf4j
24	@Service
25	@RequiredArgsConstructor
26	public class CropStageService {
27	
28	    private final CropPlantingMapper cropPlantingMapper;
29	    private final CropStageConfigMapper stageConfigMapper;
30	
31	    /**
32	     * 获取地块当前的灌溉策略
33	     *
34	     * @param pointId 检测点ID
35	     * @return 灌溉策略
36	     */
37	    public IrrigationStrategyDTO getStrategy(Long pointId) {
38	        IrrigationStrategyDTO strategy = new IrrigationStrategyDTO();
39	
40	        // 1. 获取作物种植信息
41	        CropPlanting crop = getActiveCropByPointId(pointId);
42	
43	        if (crop == null) {
44	            // 无作物配置，返回默认策略
45	            return getDefaultStrategy();
46	        }
47	
48	        // 2. 计算当前生长天数
49	        int daysSincePlanting = calculateDaysSincePlanting(crop.getPlantingDate());
50	
51	        // 3. 获取当前阶段配置
52	        CropStageConfig stage = getStageConfigByCropCodeAndDay(
53	                crop.getCropCode(), daysSincePlanting);
54	
55	        if (stage == null) {
56	            // 找不到阶段配置，使用默认值
57	            log.warn("未找到作物阶段配置: cropCode={}, days={}", crop.getCropCode(), daysSincePlanting);
58	            return getDefaultStrategy();
59	        }
60	
61	        // 4. 构建策略
62	        strategy.setHasCropConfig(true);
63	        strategy.setCropCode(crop.getCropCode());
64	        strategy.setCropName(crop.getCropName());
65	        strategy.setCurrentStage(stage.getStageName());
66	        strategy.setDaysSincePlanting(daysSincePlanting);
67	        strategy.setMinHumidity(stage.getMinHumidity());
68	        strategy.setMaxHumidity(stage.getMaxHumidity());
69	        strategy.setOptimalHumidity(stage.getOptimalHumidity());
70	        strategy.setIrrigationFactor(stage.getIrrigationFactor());
71	        strategy.setFrequencyHint(stage.getFrequencyHint());
72	        strategy.setWaterNeeds(stage.getWaterNeeds());
73	        strategy.setSpecialNotes(stage.getSpecialNotes());
74	
75	        // 5. 更新作物的当前阶段（如果阶段变化）
76	        updateCropStageIfNeeded(crop, stage.getStageCode(), stage.getStageName(), daysSincePlanting);
77	
78	        return strategy;
79	    }
80	
81	    /**
82	     * 根据作物阶段调整灌溉计划
83	     */
84	    public BigDecimal adjustWaterByStage(BigDecimal originalWaterAmount,
85	                                          IrrigationStrategyDTO strategy,
86	                                          BigDecimal currentMoisture) {
87	        if (!strategy.getHasCropConfig()) {
88	            return originalWaterAmount;
89	        }
90	
91	        // 应用灌溉系数
92	        BigDecimal adjustedWater = originalWaterAmount.multiply(strategy.getIrrigationFactor());
93	
94	        // 检查是否超出湿度范围
95	        if (strategy.getMaxHumidity() != null && currentMoisture != null) {
96	            BigDecimal maxAllowed = strategy.getMaxHumidity();
97	            if (currentMoisture.compareTo(maxAllowed) >= 0) {
98	                log.info("当前湿度{}%已达阶段最高限制{}%", currentMoisture, maxAllowed);
99	                return BigDecimal.ZERO;
100	            }
101	        }
102	
103	        log.debug("调整灌溉量: original={}, factor={}, adjusted={}",
104	                originalWaterAmount, strategy.getIrrigationFactor(), adjustedWater);
105	
106	        return adjustedWater;
107	    }
108	
109	    /**
110	     * 获取作物生长阶段列表（用于展示）
111	     */
112	    public List<CropStageConfig> getStageConfigs(String cropCode) {
113	        LambdaQueryWrapper<CropStageConfig> wrapper = new LambdaQueryWrapper<>();
114	        wrapper.eq(CropStageConfig::getCropCode, cropCode)
115	               .orderByAsc(CropStageConfig::getStageOrder);
116	        return stageConfigMapper.selectList(wrapper);
117	    }
