119	    /**
120	     * 设置或更新作物信息
121	     */
122	    @Transactional
123	    public void setCrop(Long pointId, String cropCode, String cropName, LocalDate plantingDate) {
124	        CropPlanting existing = getActiveCropByPointId(pointId);
125	
126	        if (existing != null) {
127	            existing.setCropCode(cropCode);
128	            existing.setCropName(cropName);
129	            existing.setPlantingDate(plantingDate);
130	            existing.setCurrentStage(null);
131	            existing.setStageUpdatedAt(null);
132	            cropPlantingMapper.updateById(existing);
133	            log.info("更新作物信息: pointId={}, cropCode={}", pointId, cropCode);
134	        } else {
135	            CropPlanting newCrop = new CropPlanting();
136	            newCrop.setPointId(pointId);
137	            newCrop.setCropCode(cropCode);
138	            newCrop.setCropName(cropName);
139	            newCrop.setPlantingDate(plantingDate);
140	            newCrop.setStatus(1);
141	            cropPlantingMapper.insert(newCrop);
142	            log.info("创建作物信息: pointId={}, cropCode={}", pointId, cropCode);
143	        }
144	    }
145	
146	    /**
147	     * 收获作物（标记为已完成）
148	     */
149	    @Transactional
150	    public void harvestCrop(Long pointId) {
151	        CropPlanting crop = getActiveCropByPointId(pointId);
152	        if (crop != null) {
153	            crop.setStatus(0); // 已收获
154	            cropPlantingMapper.updateById(crop);
155	            log.info("作物已收获: pointId={}", pointId);
156	        }
157	    }
158	
159	    /**
160	     * 获取检测点当前活跃的作物
161	     */
162	    private CropPlanting getActiveCropByPointId(Long pointId) {
163	        LambdaQueryWrapper<CropPlanting> wrapper = new LambdaQueryWrapper<>();
164	        wrapper.eq(CropPlanting::getPointId, pointId)
165	               .eq(CropPlanting::getStatus, 1);
166	        return cropPlantingMapper.selectOne(wrapper);
167	    }
168	
169	    /**
170	     * 根据作物编码和天数获取阶段配置
171	     */
172	    private CropStageConfig getStageConfigByCropCodeAndDay(String cropCode, int days) {
173	        LambdaQueryWrapper<CropStageConfig> wrapper = new LambdaQueryWrapper<>();
174	        wrapper.eq(CropStageConfig::getCropCode, cropCode)
175	               .le(CropStageConfig::getStartDay, days)
176	               .ge(CropStageConfig::getEndDay, days);
177	        return stageConfigMapper.selectOne(wrapper);
178	    }
