180	    /**
181	     * 计算播种以来的天数
182	     */
183	    private int calculateDaysSincePlanting(LocalDate plantingDate) {
184	        if (plantingDate == null) return 0;
185	        return (int) ChronoUnit.DAYS.between(plantingDate, LocalDate.now());
186	    }
187	
188	    /**
189	     * 如果阶段变化，更新作物记录
190	     */
191	    @Transactional
192	    protected void updateCropStageIfNeeded(CropPlanting crop, String newStageCode, String newStageName, int currentDay) {
193	        if (!newStageCode.equals(crop.getCurrentStage())) {
194	            crop.setCurrentStage(newStageName);
195	            crop.setCurrentStageDay(currentDay);
196	            crop.setStageUpdatedAt(LocalDate.now());
197	            cropPlantingMapper.updateById(crop);
198	            log.info("更新作物阶段: pointId={}, cropName={}, newStage={}",
199	                    crop.getPointId(), crop.getCropName(), newStageName);
200	        }
201	    }
