104	    private void checkAndCreateAlarms(SensorData data) {
105	        Long pointId = data.getPointId();
106	
107	        // One query for existing unprocessed alarm types per point.
108	        Set<String> existingUnprocessedTypes = new HashSet<>(alarmMapper.findUnprocessedAlarmTypesByPointId(pointId));
109	        List<Alarm> alarmsToCreate = new ArrayList<>();
110	
111	        if (data.getTemperature() != null) {
112	            if (data.getTemperature().compareTo(TEMP_MAX) > 0) {
113	                addAlarmIfNeeded(pointId, "TEMPERATURE_HIGH", data.getTemperature(), TEMP_MAX, existingUnprocessedTypes, alarmsToCreate);
114	            } else if (data.getTemperature().compareTo(TEMP_MIN) < 0) {
115	                addAlarmIfNeeded(pointId, "TEMPERATURE_LOW", data.getTemperature(), TEMP_MIN, existingUnprocessedTypes, alarmsToCreate);
116	            }
117	        }
118	
119	        if (data.getHumidity() != null) {
120	            if (data.getHumidity().compareTo(HUMIDITY_MAX) > 0) {
121	                addAlarmIfNeeded(pointId, "HUMIDITY_HIGH", data.getHumidity(), HUMIDITY_MAX, existingUnprocessedTypes, alarmsToCreate);
122	            } else if (data.getHumidity().compareTo(HUMIDITY_MIN) < 0) {
123	                addAlarmIfNeeded(pointId, "HUMIDITY_LOW", data.getHumidity(), HUMIDITY_MIN, existingUnprocessedTypes, alarmsToCreate);
124	            }
125	        }
126	
127	        if (data.getLight() != null && data.getLight().compareTo(LIGHT_MIN) < 0) {
128	            addAlarmIfNeeded(pointId, "LIGHT_LOW", data.getLight(), LIGHT_MIN, existingUnprocessedTypes, alarmsToCreate);
129	        }
130	
131	        if (data.getCo2() != null && data.getCo2().compareTo(CO2_MAX) > 0) {
132	            addAlarmIfNeeded(pointId, "CO2_HIGH", data.getCo2(), CO2_MAX, existingUnprocessedTypes, alarmsToCreate);
133	        }
134	
135	        if (data.getSoilMoisture() != null && data.getSoilMoisture().compareTo(SOIL_MOISTURE_MIN) < 0) {
136	            addAlarmIfNeeded(pointId, "SOIL_MOISTURE_LOW", data.getSoilMoisture(), SOIL_MOISTURE_MIN, existingUnprocessedTypes, alarmsToCreate);
137	        }
138	
139	        for (Alarm alarm : alarmsToCreate) {
140	            alarmMapper.insert(alarm);
141	            log.warn("创建报警: 检测点={}, 类型={}, 值={}, 阈值={}",
142	                    alarm.getPointId(), alarm.getAlarmType(), alarm.getAlarmValue(), alarm.getThreshold());
143	        }
144	    }
