146	    private void addAlarmIfNeeded(Long pointId, String alarmType, BigDecimal alarmValue, BigDecimal threshold,
147	                                  Set<String> existingUnprocessedTypes, List<Alarm> alarmsToCreate) {
148	        if (existingUnprocessedTypes.contains(alarmType)) {
149	            return;
150	        }
151	
152	        Alarm alarm = new Alarm();
153	        alarm.setPointId(pointId);
154	        alarm.setAlarmType(alarmType);
155	        alarm.setAlarmValue(alarmValue);
156	        alarm.setThreshold(threshold);
157	        alarm.setStatus(0);
158	
159	        alarmsToCreate.add(alarm);
160	        existingUnprocessedTypes.add(alarmType);
161	    }
