86	        }
87	
88	        irrigationLog.setEndTime(LocalDateTime.now());
89	
90	        if (irrigationLog.getStartTime() != null) {
91	            Duration duration = Duration.between(irrigationLog.getStartTime(), irrigationLog.getEndTime());
92	            int actualDuration = (int) duration.getSeconds();
93	            irrigationLog.setDuration(actualDuration);
