125	            plan.setRiskFactor(BigDecimal.ONE);
126	            plan.setReason("缺少环境数据");
127	            return plan;
128	        }
129	
130	        int threshold = 40;
131	        if (config != null && config.getMoistureThreshold() != null) {
132	            threshold = clamp(config.getMoistureThreshold(), 20, 70);
133	        }
134	
135	        BigDecimal soilMoisture = clamp(envData.getSoilMoisture(), BigDecimal.ZERO, new BigDecimal("100"));
136	        if (soilMoisture.compareTo(new BigDecimal(threshold)) >= 0) {
137	            return buildNoIrrigationPlan(threshold, "土壤水分超过阈值");
138	        }
139	
140	        BigDecimal targetMoisture = new BigDecimal(threshold + 12).min(new BigDecimal("75"));
141	        BigDecimal moistureGap = targetMoisture.subtract(soilMoisture).max(BigDecimal.ZERO);
142	
143	        BigDecimal baseWaterAmount = moistureGap.divide(SOIL_MOISTURE_GAIN_PER_LITER, 6, RoundingMode.HALF_UP);
144	        BigDecimal riskFactor = BigDecimal.ONE;
145	
146	        if (envData.getTemperature() != null) {
147	            if (envData.getTemperature().compareTo(new BigDecimal("35")) > 0) {
148	                riskFactor = riskFactor.add(new BigDecimal("0.2"));
149	            } else if (envData.getTemperature().compareTo(new BigDecimal("30")) > 0) {
150	                riskFactor = riskFactor.add(new BigDecimal("0.1"));
151	            } else if (envData.getTemperature().compareTo(new BigDecimal("15")) < 0) {
152	                riskFactor = riskFactor.subtract(new BigDecimal("0.08"));
153	            }
154	        }
155	
156	        if (envData.getHumidity() != null) {
157	            if (envData.getHumidity().compareTo(new BigDecimal("40")) < 0) {
158	                riskFactor = riskFactor.add(new BigDecimal("0.1"));
159	            } else if (envData.getHumidity().compareTo(new BigDecimal("75")) > 0) {
160	                riskFactor = riskFactor.subtract(new BigDecimal("0.08"));
161	            }
162	        }
163	
164	        if (envData.getLight() != null) {
165	            if (envData.getLight().compareTo(new BigDecimal("30000")) > 0) {
166	                riskFactor = riskFactor.add(new BigDecimal("0.15"));
167	            } else if (envData.getLight().compareTo(new BigDecimal("15000")) > 0) {
168	                riskFactor = riskFactor.add(new BigDecimal("0.08"));
169	            } else if (envData.getLight().compareTo(new BigDecimal("1000")) < 0) {
170	                riskFactor = riskFactor.subtract(new BigDecimal("0.05"));
171	            }
172	        }
173	
174	        if (envData.getCo2() != null && envData.getCo2().compareTo(new BigDecimal("1000")) > 0) {
175	            riskFactor = riskFactor.add(new BigDecimal("0.05"));
176	        }
177	
178	        riskFactor = clamp(riskFactor, new BigDecimal("0.75"), new BigDecimal("1.45"));
179	        BigDecimal waterAmount = baseWaterAmount.multiply(riskFactor);
180	        waterAmount = clamp(waterAmount, new BigDecimal("0.5"), new BigDecimal("45"));
181	
182	        int rawDuration = waterAmount.divide(WATER_PER_SECOND, 0, RoundingMode.HALF_UP).intValue();
183	        int durationSeconds = clamp(rawDuration, MIN_AUTO_DURATION_SEC, MAX_AUTO_DURATION_SEC);
184	
185	        plan.setShouldIrrigate(true);
186	        plan.setWaterAmountL(waterAmount.setScale(1, RoundingMode.HALF_UP));
187	        plan.setDurationSeconds(durationSeconds);
188	        plan.setTargetMoisture(targetMoisture.setScale(1, RoundingMode.HALF_UP));
189	        plan.setMoistureGap(moistureGap.setScale(1, RoundingMode.HALF_UP));
190	        plan.setRiskFactor(riskFactor.setScale(2, RoundingMode.HALF_UP));
191	        plan.setReason("根据环境和门槛自动计划");
192	        return plan;
193	    }
194	
195	    /**
196	     * Plan-only API for clients.
197	     */
198	    public AutoIrrigationPlanResponse buildAutoPlan(IrrigationPlanRequest request) {
199	        Long pointId = request != null ? request.getPointId() : null;
200	        EnvironmentDataDTO envData = request != null ? request.getEnvData() : null;
201	        IrrigationPlanConfig config = request != null ? request.getConfig() : null;
202	
203	        if (pointId == null) {
204	            pointId = 1L;
205	        }
206	        return buildAutoPlan(envData, config);
207	    }
208	
209	    /**
210	     *如果配置和时间规则允许，计算计划并开始灌溉
211	     */
212	    @Transactional
213	    public AutoIrrigationResultResponse startAutoIrrigation(AutoIrrigationRequest request) {
214	        Long pointId = request != null ? request.getPointId() : null;
215	        EnvironmentDataDTO envData = request != null ? request.getEnvData() : null;
216	        IrrigationPlanConfig config = request != null ? request.getConfig() : null;
217	
218	        if (pointId == null) {
219	            pointId = 1L;
220	        }
221	
222	        AutoIrrigationPlanResponse plan = buildAutoPlan(envData, config);
223	
224	        if (config == null || config.getAutoMode() == null || !config.getAutoMode()) {
225	            plan.setShouldIrrigate(false);
226	            plan.setReason("自动模式已禁用");
227	        }
228	
229	        if (plan.isShouldIrrigate() && isCurrentlyIrrigating(pointId)) {
230	            plan.setShouldIrrigate(false);
231	            plan.setReason("灌溉系统已经开始运行");
232	        }
233	
234	        if (plan.isShouldIrrigate()) {
235	            int minInterval = config != null && config.getMinInterval() != null ? config.getMinInterval() : 0;
236	            if (!isAutoIntervalOk(pointId, minInterval)) {
237	                plan.setShouldIrrigate(false);
238	                plan.setReason("最短间隔尚未过去");
239	            }
240	        }
241	
242	        AutoIrrigationResultResponse result = new AutoIrrigationResultResponse();
243	        result.setPlan(plan);
244	
245	        if (plan.isShouldIrrigate()) {
246	            IrrigationLog logEntity = startIrrigationInternal(pointId, plan.getDurationSeconds(), 0);
247	            result.setLog(toDTO(logEntity));
248	            result.setStarted(true);
249	        } else {
250	            result.setStarted(false);
251	            result.setLog(null);
252	        }
253	
254	        return result;
255	    }
256	
257	    private IrrigationLog startIrrigationInternal(Long pointId, Integer duration, Integer mode) {
258	        IrrigationLog irrigationLog = new IrrigationLog();
259	        irrigationLog.setPointId(pointId);
260	        irrigationLog.setDuration(duration);
261	        irrigationLog.setMode(mode);
262	        irrigationLog.setStartTime(LocalDateTime.now());
263	
264	        BigDecimal waterAmount = WATER_PER_SECOND.multiply(new BigDecimal(duration));
265	        irrigationLog.setWaterAmount(waterAmount);
266	
267	        irrigationLogMapper.insert(irrigationLog);
268	        log.info("灌溉开始： pointId={}， durationSec={}， waterAmountL={}， mode={}",
269	                pointId, duration, waterAmount, mode);
270	        return irrigationLog;
271	    }
272	
273	    private boolean isCurrentlyIrrigating(Long pointId) {
274	        IrrigationLog active = irrigationLogMapper.findActiveByPointId(pointId);
275	        return active != null;
276	    }
277	
278	    private boolean isAutoIntervalOk(Long pointId, int minIntervalSeconds) {
279	        if (minIntervalSeconds <= 0) {
280	            return true;
281	        }
282	
283	        IrrigationLog lastAuto = irrigationLogMapper.findLastAutoByPointId(pointId);
284	        if (lastAuto == null || lastAuto.getStartTime() == null) {
285	            return true;
286	        }
287	
288	        Duration elapsed = Duration.between(lastAuto.getStartTime(), LocalDateTime.now());
289	        return elapsed.getSeconds() >= minIntervalSeconds;
290	    }
291	
292	    private AutoIrrigationPlanResponse buildNoIrrigationPlan(int targetMoisture, String reason) {
293	        AutoIrrigationPlanResponse plan = new AutoIrrigationPlanResponse();
294	        plan.setShouldIrrigate(false);
295	        plan.setWaterAmountL(BigDecimal.ZERO);
296	        plan.setDurationSeconds(0);
297	        plan.setTargetMoisture(new BigDecimal(targetMoisture).setScale(1, RoundingMode.HALF_UP));
298	        plan.setMoistureGap(BigDecimal.ZERO);
299	        plan.setRiskFactor(BigDecimal.ONE);
300	        plan.setReason(reason);
301	        return plan;
302	    }
303	
304	    private int clamp(int value, int min, int max) {
305	        return Math.max(min, Math.min(max, value));
306	    }
307	
308	    private BigDecimal clamp(BigDecimal value, BigDecimal min, BigDecimal max) {
309	        if (value.compareTo(min) < 0) {
310	            return min;
311	        }
312	        if (value.compareTo(max) > 0) {
313	            return max;
314	        }
315	        return value;
316	    }
317	
318	    private IrrigationDTO toDTO(IrrigationLog irrigationLog) {
319	        IrrigationDTO dto = new IrrigationDTO();
320	        dto.setId(irrigationLog.getId());
321	        dto.setPointId(irrigationLog.getPointId());
322	        dto.setWaterAmount(irrigationLog.getWaterAmount());
323	        dto.setDuration(irrigationLog.getDuration());
324	        dto.setMode(irrigationLog.getMode());
325	        dto.setStartTime(irrigationLog.getStartTime());
326	        dto.setEndTime(irrigationLog.getEndTime());
327	        dto.setCreatedAt(irrigationLog.getCreatedAt());
328	        return dto;
329	    }
330	}
