162	    /**
163	     * 灌溉完成后的学习和更新
164	     */
165	    @Transactional
166	    public void onIrrigationComplete(Long logId, BigDecimal soilMoistureAfter) {
167	        IrrigationLog irrigationLog = irrigationLogMapper.selectById(logId);
168	        if (irrigationLog == null) {
169	            return;
170	        }
171	
172	        irrigationLog.setEndTime(LocalDateTime.now());
173	        irrigationLog.setSoilMoistureAfter(soilMoistureAfter);
174	
175	        irrigationLogMapper.updateById(irrigationLog);
