177	
178	        BigDecimal actualGain = null;
179	        if (irrigationLog.getSoilMoistureBefore() != null && soilMoistureAfter != null) {
180	            actualGain = soilMoistureAfter.subtract(irrigationLog.getSoilMoistureBefore());
181	        }
182	        log.info("灌溉完成并学习: logId={}, actualGain={}", logId, actualGain);
183	    }
