192	        stats.setCropStrategy(cropStageService.getStrategy(pointId));
193	
194	        // 获取最近灌溉记录（包含决策数据）
195	        LambdaQueryWrapper<IrrigationLog> wrapper = new LambdaQueryWrapper<>();
196	        wrapper.eq(IrrigationLog::getPointId, pointId)
