204	    // ========== 私有方法 ==========
205	
206	    private int getThreshold(IrrigationPlanConfig config) {
207	        if (config != null && config.getMoistureThreshold() != null) {
208	            return Math.max(20, Math.min(70, config.getMoistureThreshold()));
209	        }
210	        return 40;
211	    }
212	
213	    private BigDecimal calculateTargetMoisture(int threshold, IrrigationStrategyDTO strategy) {
214	        if (strategy.getOptimalHumidity() != null) {
215	            return strategy.getOptimalHumidity();
216	        }
217	
218	        BigDecimal target = BigDecimal.valueOf(threshold + 12);
219	        if (strategy.getMaxHumidity() != null) {
220	            target = target.min(strategy.getMaxHumidity());
221	        }
222	        return target.min(new BigDecimal("75"));
223	    }
224	
225	    private BigDecimal calculateRiskFactor(EnvironmentDataDTO envData) {
226	        BigDecimal factor = BigDecimal.ONE;
227	
228	        if (envData.getTemperature() != null) {
229	            BigDecimal temp = envData.getTemperature();
230	            if (temp.compareTo(new BigDecimal("35")) > 0) {
231	                factor = factor.add(new BigDecimal("0.2"));
232	            } else if (temp.compareTo(new BigDecimal("30")) > 0) {
233	                factor = factor.add(new BigDecimal("0.1"));
234	            } else if (temp.compareTo(new BigDecimal("15")) < 0) {
235	                factor = factor.subtract(new BigDecimal("0.08"));
236	            }
237	        }
238	
239	        if (envData.getHumidity() != null) {
240	            BigDecimal humidity = envData.getHumidity();
241	            if (humidity.compareTo(new BigDecimal("40")) < 0) {
242	                factor = factor.add(new BigDecimal("0.1"));
243	            } else if (humidity.compareTo(new BigDecimal("75")) > 0) {
244	                factor = factor.subtract(new BigDecimal("0.08"));
245	            }
246	        }
247	
248	        if (envData.getLight() != null) {
249	            BigDecimal light = envData.getLight();
250	            if (light.compareTo(new BigDecimal("30000")) > 0) {
251	                factor = factor.add(new BigDecimal("0.15"));
252	            } else if (light.compareTo(new BigDecimal("15000")) > 0) {
253	                factor = factor.add(new BigDecimal("0.08"));
254	            }
255	        }
256	
257	        return clamp(factor, new BigDecimal("0.75"), new BigDecimal("1.45"));
258	    }
259	
260	    private BigDecimal clamp(BigDecimal value, BigDecimal min, BigDecimal max) {
261	        if (value.compareTo(min) < 0) return min;
262	        if (value.compareTo(max) > 0) return max;
263	        return value;
264	    }
