1	package com.agriculture.service;
2	
3	import com.agriculture.entity.CropPlanting;
4	import com.agriculture.entity.CropStageConfig;
5	import com.agriculture.mapper.CropPlantingMapper;
6	import com.agriculture.mapper.CropStageConfigMapper;
7	import com.agriculture.model.dto.IrrigationStrategyDTO;
8	import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
9	import lombok.RequiredArgsConstructor;
10	import lombok.extern.slf4j.Slf4j;
11	import org.springframework.stereotype.Service;
12	import org.springframework.transaction.annotation.Transactional;
13	
14	import java.math.BigDecimal;
15	import java.time.LocalDate;
16	import java.time.temporal.ChronoUnit;
17	import java.util.List;
18	
19	/**
20	 * 作物生长阶段服务
21	 * 根据作物生长周期动态调整灌溉策略
22	 */
23	@Slf4j
24	@Service
25	@RequiredArgsConstructor
26	public class CropStageService {
27	
28	    private final CropPlantingMapper cropPlantingMapper;
29	    private final CropStageConfigMapper stageConfigMapper;
30	
31	    /**
32	     * 获取地块当前的灌溉策略
33	     *
34	     * @param pointId 检测点ID
35	     * @return 灌溉策略
36	     */
37	    public IrrigationStrategyDTO getStrategy(Long pointId) {
38	        IrrigationStrategyDTO strategy = new IrrigationStrategyDTO();
39	
40	        // 1. 获取作物种植信息
41	        CropPlanting crop = getActiveCropByPointId(pointId);
42	
43	        if (crop == null) {
44	            // 无作物配置，返回默认策略
45	            return getDefaultStrategy();
46	        }
47	
48	        // 2. 计算当前生长天数
49	        int daysSincePlanting = calculateDaysSincePlanting(crop.getPlantingDate());
50	
51	        // 3. 获取当前阶段配置
52	        CropStageConfig stage = getStageConfigByCropCodeAndDay(
53	                crop.getCropCode(), daysSincePlanting);
54	
55	        if (stage == null) {
56	            // 找不到阶段配置，使用默认值
57	            log.warn("未找到作物阶段配置: cropCode={}, days={}", crop.getCropCode(), daysSincePlanting);
58	            return getDefaultStrategy();
59	        }
60	
61	        // 4. 构建策略
62	        strategy.setHasCropConfig(true);
63	        strategy.setCropCode(crop.getCropCode());
64	        strategy.setCropName(crop.getCropName());
65	        strategy.setCurrentStage(stage.getStageName());
66	        strategy.setDaysSincePlanting(daysSincePlanting);
67	        strategy.setMinHumidity(stage.getMinHumidity());
68	        strategy.setMaxHumidity(stage.getMaxHumidity());
69	        strategy.setOptimalHumidity(stage.getOptimalHumidity());
70	        strategy.setIrrigationFactor(stage.getIrrigationFactor());
71	        strategy.setFrequencyHint(stage.getFrequencyHint());
72	        strategy.setWaterNeeds(stage.getWaterNeeds());
73	        strategy.setSpecialNotes(stage.getSpecialNotes());
74	
75	        // 5. 更新作物的当前阶段（如果阶段变化）
76	        updateCropStageIfNeeded(crop, stage.getStageCode(), stage.getStageName(), daysSincePlanting);
77	
78	        return strategy;
79	    }
80	
81	    /**
82	     * 根据作物阶段调整灌溉计划
83	     */
84	    public BigDecimal adjustWaterByStage(BigDecimal originalWaterAmount,
85	                                          IrrigationStrategyDTO strategy,
86	                                          BigDecimal currentMoisture) {
87	        if (!strategy.getHasCropConfig()) {
88	            return originalWaterAmount;
89	        }
90	
91	        // 应用灌溉系数
92	        BigDecimal adjustedWater = originalWaterAmount.multiply(strategy.getIrrigationFactor());
93	
94	        // 检查是否超出湿度范围
95	        if (strategy.getMaxHumidity() != null && currentMoisture != null) {
96	            BigDecimal maxAllowed = strategy.getMaxHumidity();
97	            if (currentMoisture.compareTo(maxAllowed) >= 0) {
98	                log.info("当前湿度{}%已达阶段最高限制{}%", currentMoisture, maxAllowed);
99	                return BigDecimal.ZERO;
100	            }
101	        }
102	
103	        log.debug("调整灌溉量: original={}, factor={}, adjusted={}",
104	                originalWaterAmount, strategy.getIrrigationFactor(), adjustedWater);
105	
106	        return adjustedWater;
107	    }
108	
109	    /**
110	     * 获取作物生长阶段列表（用于展示）
111	     */
112	    public List<CropStageConfig> getStageConfigs(String cropCode) {
113	        LambdaQueryWrapper<CropStageConfig> wrapper = new LambdaQueryWrapper<>();
114	        wrapper.eq(CropStageConfig::getCropCode, cropCode)
115	               .orderByAsc(CropStageConfig::getStageOrder);
116	        return stageConfigMapper.selectList(wrapper);
117	    }
118	
119	    /**
120	     * 设置或更新作物信息
121	     */
122	    @Transactional
123	    public void setCrop(Long pointId, String cropCode, String cropName, LocalDate plantingDate) {
124	        CropPlanting existing = getActiveCropByPointId(pointId);
125	
126	        if (existing != null) {
127	            existing.setCropCode(cropCode);
128	            existing.setCropName(cropName);
129	            existing.setPlantingDate(plantingDate);
130	            existing.setCurrentStage(null);
131	            existing.setStageUpdatedAt(null);
132	            cropPlantingMapper.updateById(existing);
133	            log.info("更新作物信息: pointId={}, cropCode={}", pointId, cropCode);
134	        } else {
135	            CropPlanting newCrop = new CropPlanting();
136	            newCrop.setPointId(pointId);
137	            newCrop.setCropCode(cropCode);
138	            newCrop.setCropName(cropName);
139	            newCrop.setPlantingDate(plantingDate);
140	            newCrop.setStatus(1);
141	            cropPlantingMapper.insert(newCrop);
142	            log.info("创建作物信息: pointId={}, cropCode={}", pointId, cropCode);
143	        }
144	    }
145	
146	    /**
147	     * 收获作物（标记为已完成）
148	     */
149	    @Transactional
150	    public void harvestCrop(Long pointId) {
151	        CropPlanting crop = getActiveCropByPointId(pointId);
152	        if (crop != null) {
153	            crop.setStatus(0); // 已收获
154	            cropPlantingMapper.updateById(crop);
155	            log.info("作物已收获: pointId={}", pointId);
156	        }
157	    }
158	
159	    /**
160	     * 获取检测点当前活跃的作物
161	     */
162	    private CropPlanting getActiveCropByPointId(Long pointId) {
163	        LambdaQueryWrapper<CropPlanting> wrapper = new LambdaQueryWrapper<>();
164	        wrapper.eq(CropPlanting::getPointId, pointId)
165	               .eq(CropPlanting::getStatus, 1);
166	        return cropPlantingMapper.selectOne(wrapper);
167	    }
168	
169	    /**
170	     * 根据作物编码和天数获取阶段配置
171	     */
172	    private CropStageConfig getStageConfigByCropCodeAndDay(String cropCode, int days) {
173	        LambdaQueryWrapper<CropStageConfig> wrapper = new LambdaQueryWrapper<>();
174	        wrapper.eq(CropStageConfig::getCropCode, cropCode)
175	               .le(CropStageConfig::getStartDay, days)
176	               .ge(CropStageConfig::getEndDay, days);
177	        return stageConfigMapper.selectOne(wrapper);
178	    }
179	
180	    /**
181	     * 计算播种以来的天数
182	     */
183	    private int calculateDaysSincePlanting(LocalDate plantingDate) {
184	        if (plantingDate == null) return 0;
185	        return (int) ChronoUnit.DAYS.between(plantingDate, LocalDate.now());
186	    }
187	
188	    /**
189	     * 如果阶段变化，更新作物记录
190	     */
191	    @Transactional
192	    protected void updateCropStageIfNeeded(CropPlanting crop, String newStageCode, String newStageName, int currentDay) {
193	        if (!newStageCode.equals(crop.getCurrentStage())) {
194	            crop.setCurrentStage(newStageName);
195	            crop.setCurrentStageDay(currentDay);
196	            crop.setStageUpdatedAt(LocalDate.now());
197	            cropPlantingMapper.updateById(crop);
198	            log.info("更新作物阶段: pointId={}, cropName={}, newStage={}",
199	                    crop.getPointId(), crop.getCropName(), newStageName);
200	        }
201	    }
202	
203	    /**
204	     * 获取默认策略（无作物配置时使用）
205	     */
206	    private IrrigationStrategyDTO getDefaultStrategy() {
207	        IrrigationStrategyDTO strategy = new IrrigationStrategyDTO();
208	        strategy.setHasCropConfig(false);
209	        strategy.setMinHumidity(new BigDecimal("40"));
210	        strategy.setMaxHumidity(new BigDecimal("75"));
211	        strategy.setOptimalHumidity(new BigDecimal("52"));
212	        strategy.setIrrigationFactor(BigDecimal.ONE);
213	        strategy.setFrequencyHint("根据环境自动调整");
214	        return strategy;
215	    }
216	
217	    /**
218	     * 获取支持的作物类型列表
219	     */
220	    public String[] getSupportedCropCodes() {
221	        return new String[]{
222	                "tomato", "cucumber", "pepper", "eggplant",
223	                "rice", "corn", "vegetable", "strawberry", "watermelon", "cabbage"
224	        };
225	    }
226	
227	    /**
228	     * 获取支持的作物类型列表（兼容旧方法名）
229	     */
230	    public String[] getSupportedCropTypes() {
231	        return getSupportedCropCodes();
232	    }
233	
234	    /**
235	     * 获取作物类型的中文名称
236	     */
237	    public String getCropName(String cropCode) {
238	        switch (cropCode) {
239	            case "tomato": return "番茄";
240	            case "cucumber": return "黄瓜";
241	            case "pepper": return "辣椒";
242	            case "eggplant": return "茄子";
243	            case "rice": return "水稻";
244	            case "corn": return "玉米";
245	            case "vegetable": return "蔬菜";
246	            case "strawberry": return "草莓";
247	            case "watermelon": return "西瓜";
248	            case "cabbage": return "白菜";
249	            default: return cropCode;
250	        }
251	    }
252	
253	    /**
254	     * 获取作物类型的中文名称（兼容旧方法名）
255	     */
256	    public String getCropTypeName(String cropCode) {
257	        return getCropName(cropCode);
258	    }
259	}

