1	package com.agriculture.service;
2	
3	import com.agriculture.entity.SensorData;
4	import com.agriculture.mapper.SensorDataMapper;
5	import com.agriculture.model.dto.MoisturePredictionDTO;
6	import lombok.RequiredArgsConstructor;
7	import lombok.extern.slf4j.Slf4j;
8	import org.springframework.stereotype.Service;
9	
10	import java.math.BigDecimal;
11	import java.math.RoundingMode;
12	import java.time.LocalDateTime;
13	import java.util.List;
14	import java.util.stream.Collectors;
15	
16	/**
17	 * EWMA湿度预测服务
18	 * 使用指数加权移动平均进行湿度趋势预测
19	 * 直接从 sensor_data 表读取历史数据，无需额外建表
20	 */
21	@Slf4j
22	@Service
23	@RequiredArgsConstructor
24	public class MoisturePredictor {
25	
26	    private final SensorDataMapper sensorDataMapper;
27	
28	    // EWMA衰减因子，越大越重视近期数据
29	    private static final double ALPHA = 0.3;
30	
31	    // 趋势计算窗口大小
32	    private static final int TREND_WINDOW = 3;
33	
34	    /**
35	     * 预测未来湿度变化
36	     *
37	     * @param pointId    检测点ID
38	     * @param hoursAhead 预测未来几小时
39	     * @return 预测结果
40	     */
41	    public MoisturePredictionDTO predict(Long pointId, int hoursAhead) {
42	        MoisturePredictionDTO result = new MoisturePredictionDTO();
43	
44	        // 获取过去24小时的历史数据（从sensor_data表）
45	        LocalDateTime startTime = LocalDateTime.now().minusHours(24);
46	        LocalDateTime endTime = LocalDateTime.now();
47	        List<SensorData> sensorDataList = sensorDataMapper.findByPointIdAndTimeRange(pointId, startTime, endTime);
48	
49	        if (sensorDataList == null || sensorDataList.isEmpty()) {
50	            result.setNeedPreIrrigation(false);
51	            result.setReason("无历史数据，无法预测");
52	            result.setConfidence(BigDecimal.ZERO);
53	            return result;
54	        }
55	
56	        // 提取土壤湿度值（按时间正序排列）
57	        List<Double> history = sensorDataList.stream()
58	                .sorted((a, b) -> a.getRecordedAt().compareTo(b.getRecordedAt()))
59	                .map(d -> d.getSoilMoisture().doubleValue())
60	                .collect(Collectors.toList());
61	
62	        // 计算EWMA平滑值
63	        double ewma = calculateEWMA(history);
64	
65	        // 计算趋势
66	        double trend = calculateTrend(history);
67	
68	        // 当前湿度
69	        double current = history.get(history.size() - 1);
70	        result.setCurrentMoisture(BigDecimal.valueOf(current).setScale(1, RoundingMode.HALF_UP));
71	
72	        // 预测未来值
73	        double predict2h = ewma + trend * 2;
74	        double predict4h = ewma + trend * 4;
75	        double predict6h = ewma + trend * 6;
76	
77	        result.setPredict2h(BigDecimal.valueOf(predict2h).setScale(1, RoundingMode.HALF_UP));
78	        result.setPredict4h(BigDecimal.valueOf(predict4h).setScale(1, RoundingMode.HALF_UP));
79	        result.setPredict6h(BigDecimal.valueOf(predict6h).setScale(1, RoundingMode.HALF_UP));
80	
81	        // 判断趋势
82	        if (trend > 0.5) {
83	            result.setTrend("rising");
84	        } else if (trend < -0.5) {
85	            result.setTrend("falling");
86	        } else {
87	            result.setTrend("stable");
88	        }
89	
90	        // 计算置信度（基于数据量）
91	        double confidence = Math.min(0.9, 0.3 + history.size() * 0.02);
92	        result.setConfidence(BigDecimal.valueOf(confidence).setScale(2, RoundingMode.HALF_UP));
93	
94	        return result;
95	    }
96	
97	    /**
98	     * 分析是否需要预防性灌溉
99	     *
100	     * @param pointId   检测点ID
101	     * @param threshold 湿度阈值
102	     * @return 预测分析结果
103	     */
104	    public MoisturePredictionDTO analyze(Long pointId, double threshold) {
105	        MoisturePredictionDTO result = predict(pointId, 4);
106	
107	        if (result.getCurrentMoisture() == null) {
108	            return result;
109	        }
110	
111	        double current = result.getCurrentMoisture().doubleValue();
112	        double predict2h = result.getPredict2h() != null ? result.getPredict2h().doubleValue() : current;
113	        double predict4h = result.getPredict4h() != null ? result.getPredict4h().doubleValue() : current;
114	
115	        // 下降趋势且预测值低于阈值
116	        if ("falling".equals(result.getTrend()) && predict2h < threshold && current >= threshold) {
117	            result.setNeedPreIrrigation(true);
118	            result.setReason(String.format("预测2小时后湿度将降至%.1f%%，建议提前灌溉", predict2h));
119	        } else if (predict4h < threshold * 0.9) {
120	            // 预测值接近危险线
121	            result.setNeedPreIrrigation(true);
122	            result.setReason(String.format("预测4小时后湿度将降至%.1f%%，接近临界值", predict4h));
123	        } else {
124	            result.setNeedPreIrrigation(false);
125	            if (current < threshold) {
126	                result.setReason("当前湿度已低于阈值，需要立即灌溉");
127	            } else {
128	                result.setReason("湿度正常，无需预防性灌溉");
129	            }
130	        }
131	
132	        return result;
133	    }
134	
135	    /**
136	     * 预测指定小时后的湿度
137	     *
138	     * @param pointId    检测点ID
139	     * @param hoursAhead 预测时长
140	     * @return 预测湿度值
141	     */
142	    public double predictValue(Long pointId, int hoursAhead) {
143	        LocalDateTime startTime = LocalDateTime.now().minusHours(24);
144	        LocalDateTime endTime = LocalDateTime.now();
145	        List<SensorData> sensorDataList = sensorDataMapper.findByPointIdAndTimeRange(pointId, startTime, endTime);
146	
147	        if (sensorDataList == null || sensorDataList.isEmpty()) {
148	            return -1;
149	        }
150	
151	        List<Double> history = sensorDataList.stream()
152	                .sorted((a, b) -> a.getRecordedAt().compareTo(b.getRecordedAt()))
153	                .map(d -> d.getSoilMoisture().doubleValue())
154	                .collect(Collectors.toList());
155	
156	        double ewma = calculateEWMA(history);
157	        double trend = calculateTrend(history);
158	
159	        return ewma + trend * hoursAhead;
160	    }
161	
162	    /**
163	     * 计算EWMA平滑值
164	     */
165	    private double calculateEWMA(List<Double> history) {
166	        if (history.isEmpty()) return 0;
167	
168	        double ewma = history.get(0);
169	        for (int i = 1; i < history.size(); i++) {
170	            ewma = ALPHA * history.get(i) + (1 - ALPHA) * ewma;
171	        }
172	        return ewma;
173	    }
174	
175	    /**
176	     * 计算趋势（最近几个点的平均变化率）
177	     */
178	    private double calculateTrend(List<Double> history) {
179	        if (history.size() < 2) return 0;
180	
181	        int window = Math.min(TREND_WINDOW, history.size() - 1);
182	        double trend = 0;
183	
184	        for (int i = history.size() - window; i < history.size(); i++) {
185	            trend += history.get(i) - history.get(i - 1);
186	        }
187	
188	        return trend / window;
189	    }
190	}

1	package com.agriculture.service;
2	
3	import com.agriculture.entity.IrrigationThresholdConfig;
4	import com.agriculture.entity.IrrigationLog;
5	import com.agriculture.mapper.IrrigationThresholdConfigMapper;
6	import com.agriculture.mapper.IrrigationLogMapper;
7	import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
8	import lombok.RequiredArgsConstructor;
9	import lombok.extern.slf4j.Slf4j;
10	import org.springframework.stereotype.Service;
11	import org.springframework.transaction.annotation.Transactional;
12	
13	import java.math.BigDecimal;
14	import java.math.RoundingMode;
15	import java.time.LocalDateTime;
16	import java.util.HashMap;
17	import java.util.Map;
18	
19	/**
20	 * 灌溉自适应学习服务
21	 * 根据每次灌溉的实际效果自动调整参数
22	 */
23	@Slf4j
24	@Service
25	@RequiredArgsConstructor
26	public class IrrigationLearningService {
27	
28	    private final IrrigationThresholdConfigMapper configMapper;
29	
30	    // 默认参数值
31	    private static final BigDecimal DEFAULT_MOISTURE_GAIN = new BigDecimal("1.5000");
32	    private static final BigDecimal DEFAULT_EVAPORATION_RATE = new BigDecimal("0.5");
33	    private static final BigDecimal DEFAULT_TEMP_FACTOR = BigDecimal.ONE;
34	
35	    // 学习率上限
36	    private static final double MAX_LEARNING_RATE = 0.3;
37	    private static final double MIN_LEARNING_RATE = 0.05;
38	
39	    /**
40	     * 从灌溉完成事件中学习
41	     */
42	    @Transactional
43	    public void learn(IrrigationLog irrigationLog) {
44	        if (irrigationLog.getSoilMoistureAfter() == null || irrigationLog.getSoilMoistureBefore() == null) {
45	            log.debug("灌溉日志缺少湿度数据，跳过学习");
46	            return;
47	        }
48	
49	        if (irrigationLog.getWaterAmount() == null || irrigationLog.getWaterAmount().compareTo(BigDecimal.ZERO) <= 0) {
50	            log.debug("灌溉日志缺少用水量数据，跳过学习");
51	            return;
52	        }
53	
54	        // 计算实际效果
55	        BigDecimal actualGain = irrigationLog.getSoilMoistureAfter().subtract(irrigationLog.getSoilMoistureBefore());
56	        if (actualGain.compareTo(BigDecimal.ZERO) <= 0) {
57	            log.warn("灌溉后湿度未提升，可能存在数据异常");
58	            return;
59	        }
60	
61	        // 计算实际的"每升水提升湿度"
62	        BigDecimal actualGainPerLiter = actualGain.divide(irrigationLog.getWaterAmount(), 4, RoundingMode.HALF_UP);
63	
64	        // 更新学习参数
65	        updateLearnedMoistureGain(irrigationLog.getPointId(), actualGainPerLiter);
66	
67	        log.info("学习完成: pointId={}, 实际每升提升湿度={}", irrigationLog.getPointId(), actualGainPerLiter);
68	    }
69	
70	    /**
71	     * 获取检测点的阈值配置
72	     */
73	    public IrrigationThresholdConfig getThresholdConfig(Long pointId) {
74	        LambdaQueryWrapper<IrrigationThresholdConfig> wrapper = new LambdaQueryWrapper<>();
75	        wrapper.eq(IrrigationThresholdConfig::getPointId, pointId);
76	        IrrigationThresholdConfig config = configMapper.selectOne(wrapper);
77	        
78	        if (config == null) {
79	            // 创建默认配置
80	            config = createDefaultConfig(pointId);
81	        }
82	        
83	        return config;
84	    }
85	
86	    /**
87	     * 获取学习到的湿度提升率
88	     */
89	    public BigDecimal getLearnedMoistureGain(Long pointId) {
90	        IrrigationThresholdConfig config = getThresholdConfig(pointId);
91	        if (config.getLearnedMoistureGain() != null 
92	                && config.getLearningConfidence() != null 
93	                && config.getLearningConfidence().compareTo(new BigDecimal("0.5")) >= 0) {
94	            return config.getLearnedMoistureGain();
95	        }
96	        return DEFAULT_MOISTURE_GAIN;
97	    }
98	
99	    /**
100	     * 获取某检测点的所有学习参数
101	     */
102	    public Map<String, BigDecimal> getAllLearnedParams(Long pointId) {
103	        Map<String, BigDecimal> params = new HashMap<>();
104	        params.put("MOISTURE_GAIN_PER_LITER", DEFAULT_MOISTURE_GAIN);
105	        params.put("EVAPORATION_RATE", DEFAULT_EVAPORATION_RATE);
106	        params.put("TEMP_FACTOR", DEFAULT_TEMP_FACTOR);
107	
108	        IrrigationThresholdConfig config = getThresholdConfig(pointId);
109	        if (config != null && config.getLearnedMoistureGain() != null 
110	                && config.getLearningConfidence() != null 
111	                && config.getLearningConfidence().compareTo(new BigDecimal("0.5")) >= 0) {
112	            params.put("MOISTURE_GAIN_PER_LITER", config.getLearnedMoistureGain());
113	        }
114	
115	        return params;
116	    }
117	
118	    /**
119	     * 获取学习进度（用于前端展示）
120	     */
121	    public Map<String, Object> getLearningProgress(Long pointId) {
122	        Map<String, Object> progress = new HashMap<>();
123	        IrrigationThresholdConfig config = getThresholdConfig(pointId);
124	
125	        Map<String, Object> moistureGainInfo = new HashMap<>();
126	        moistureGainInfo.put("value", config.getLearnedMoistureGain() != null ? config.getLearnedMoistureGain() : DEFAULT_MOISTURE_GAIN);
127	        moistureGainInfo.put("confidence", config.getLearningConfidence() != null ? config.getLearningConfidence() : new BigDecimal("0.00"));
128	        moistureGainInfo.put("sampleCount", config.getLearningSampleCount() != null ? config.getLearningSampleCount() : 0);
129	        progress.put("MOISTURE_GAIN_PER_LITER", moistureGainInfo);
130	
131	        return progress;
132	    }
133	
134	    /**
135	     * 更新学习参数
136	     */
137	    @Transactional
138	    protected void updateLearnedMoistureGain(Long pointId, BigDecimal newValue) {
139	        IrrigationThresholdConfig config = getThresholdConfig(pointId);
140	
141	        int newCount = (config.getLearningSampleCount() != null ? config.getLearningSampleCount() : 0) + 1;
142	        BigDecimal oldValue = config.getLearnedMoistureGain() != null ? config.getLearnedMoistureGain() : DEFAULT_MOISTURE_GAIN;
143	
144	        // 学习率随样本数递减
145	        double learningRate = Math.max(MIN_LEARNING_RATE,
146	                Math.min(MAX_LEARNING_RATE, 1.0 / Math.min(newCount, 10)));
147	
148	        BigDecimal updatedValue = oldValue.multiply(BigDecimal.valueOf(1 - learningRate))
149	                .add(newValue.multiply(BigDecimal.valueOf(learningRate)));
150	
151	        // 更新置信度
152	        BigDecimal newConfidence = BigDecimal.valueOf(
153	                Math.min(0.95, 0.30 + newCount * 0.05));
154	
155	        config.setLearnedMoistureGain(updatedValue.setScale(4, RoundingMode.HALF_UP));
156	        config.setLearningSampleCount(newCount);
157	        config.setLearningConfidence(newConfidence.setScale(2, RoundingMode.HALF_UP));
158	        config.setLastLearningAt(LocalDateTime.now());
159	        
160	        configMapper.updateById(config);
161	
162	        log.info("更新学习参数: pointId={}, oldValue={}, newValue={}, confidence={}",
163	                pointId, oldValue, updatedValue, newConfidence);
164	    }
165	
166	    /**
167	     * 创建默认配置
168	     */
169	    private IrrigationThresholdConfig createDefaultConfig(Long pointId) {
170	        IrrigationThresholdConfig config = new IrrigationThresholdConfig();
171	        config.setPointId(pointId);
172	        config.setMoistureThreshold(40);
173	        config.setMaxSingleIrrigation(180);
174	        config.setMinIrrigationInterval(30);
175	        config.setEnablePredictive(1);
176	        config.setEnableAutoControl(1);
177	        config.setPredictionMode("ewma");
178	        config.setLearnedMoistureGain(DEFAULT_MOISTURE_GAIN);
179	        config.setLearningSampleCount(0);
180	        config.setLearningConfidence(new BigDecimal("0.00"));
181	        
182	        configMapper.insert(config);
183	        return config;
184	    }
185	
186	    /**
187	     * 根据学习参数调整用水量
188	     */
189	    public BigDecimal adjustWaterAmount(Long pointId, BigDecimal baseAmount) {
190	        BigDecimal moistureGain = getLearnedMoistureGain(pointId);
191	
192	        // 使用学习到的参数重新计算
193	        BigDecimal adjusted = baseAmount.multiply(DEFAULT_MOISTURE_GAIN)
194	                .divide(moistureGain, 4, RoundingMode.HALF_UP);
195	
196	        log.debug("调整用水量: base={}, adjusted={}, moistureGain={}",
197	                baseAmount, adjusted, moistureGain);
198	
199	        return adjusted;
200	    }
201	}

