package com.agriculture.service.impl;

import com.agriculture.common.exception.InvalidOperationException;
import com.agriculture.common.exception.ResourceNotFoundException;
import com.agriculture.model.dto.AlarmDTO;
import com.agriculture.entity.Alarm;
import com.agriculture.mapper.AlarmMapper;
import com.agriculture.service.AlarmService;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.List;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class AlarmServiceImpl implements AlarmService {

    private final AlarmMapper alarmMapper;

    @Override
    public List<AlarmDTO> getAllAlarms() {
        return alarmMapper.findAllByOrderByCreatedAtDesc().stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }

    @Override
    public Page<AlarmDTO> getAlarmsPaged(int pageNum, int pageSize) {
        Page<Alarm> page = new Page<>(pageNum + 1, pageSize);
        LambdaQueryWrapper<Alarm> wrapper = new LambdaQueryWrapper<>();
        wrapper.orderByDesc(Alarm::getCreatedAt);
        Page<Alarm> alarmPage = alarmMapper.selectPage(page, wrapper);

        Page<AlarmDTO> dtoPage = new Page<>(pageNum + 1, pageSize);
        dtoPage.setTotal(alarmPage.getTotal());
        dtoPage.setRecords(alarmPage.getRecords().stream().map(this::toDTO).collect(Collectors.toList()));
        return dtoPage;
    }

    @Override
    public List<AlarmDTO> getAlarmsByPointId(Long pointId) {
        return alarmMapper.findByPointIdOrderByCreatedAtDesc(pointId).stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }

    @Override
    public List<AlarmDTO> getUnprocessedAlarms() {
        return alarmMapper.findByStatusOrderByCreatedAtDesc(0).stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }

    @Override
    public Page<AlarmDTO> getUnprocessedAlarmsPaged(int pageNum, int pageSize) {
        Page<Alarm> page = new Page<>(pageNum + 1, pageSize);
        LambdaQueryWrapper<Alarm> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(Alarm::getStatus, 0)
                .orderByDesc(Alarm::getCreatedAt);
        Page<Alarm> alarmPage = alarmMapper.selectPage(page, wrapper);

        Page<AlarmDTO> dtoPage = new Page<>(pageNum + 1, pageSize);
        dtoPage.setTotal(alarmPage.getTotal());
        dtoPage.setRecords(alarmPage.getRecords().stream().map(this::toDTO).collect(Collectors.toList()));
        return dtoPage;
    }

    @Override
    public Long getUnprocessedCount() {
        return alarmMapper.countUnprocessed();
    }

    @Override
    public Long getUnprocessedCountByPointId(Long pointId) {
        return alarmMapper.countUnprocessedByPointId(pointId);
    }

    @Override
    public AlarmDTO getAlarmById(Long id) {
        Alarm alarm = alarmMapper.selectById(id);
        return alarm != null ? toDTO(alarm) : null;
    }

    @Override
    @Transactional
    public AlarmDTO handleAlarm(Long id, String remark) {
        Alarm alarm = alarmMapper.selectById(id);
        if (alarm == null) {
            throw new ResourceNotFoundException("报警记录", id);
        }

        if (alarm.getStatus() == 1) {
            throw new InvalidOperationException("报警已处理");
        }

        alarm.setStatus(1);
        alarm.setHandledAt(LocalDateTime.now());

        alarmMapper.updateById(alarm);
        log.info("处理报警: ID={}, 类型={}", id, alarm.getAlarmType());

        return toDTO(alarm);
    }

    @Override
    @Transactional
    public void handleAllByPointId(Long pointId) {
        LocalDateTime now = LocalDateTime.now();
        int affected = alarmMapper.handleAllByPointId(pointId, now);
        log.info("处理检测点{}的所有未处理报警, 共{}条", pointId, affected);
    }

    @Override
    @Transactional
    public void deleteAlarm(Long id) {
        alarmMapper.deleteById(id);
    }

    private AlarmDTO toDTO(Alarm alarm) {
        AlarmDTO dto = new AlarmDTO();
        dto.setId(alarm.getId());
        dto.setPointId(alarm.getPointId());
        dto.setAlarmType(alarm.getAlarmType());
        dto.setAlarmValue(alarm.getAlarmValue());
        dto.setThreshold(alarm.getThreshold());
        dto.setStatus(alarm.getStatus());
        dto.setCreatedAt(alarm.getCreatedAt());
        dto.setHandledAt(alarm.getHandledAt());
        return dto;
    }
}

package com.agriculture.service.impl;

import com.agriculture.common.exception.DuplicateResourceException;
import com.agriculture.common.exception.ResourceNotFoundException;
import com.agriculture.model.dto.DeviceDTO;
import com.agriculture.entity.Device;
import com.agriculture.mapper.DeviceMapper;
import com.agriculture.service.DeviceService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class DeviceServiceImpl implements DeviceService {

    private final DeviceMapper deviceMapper;

    @Override
    public List<DeviceDTO> getAllDevices() {
        return deviceMapper.selectList(null).stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }

    @Override
    public List<DeviceDTO> getDevicesByPointId(Long pointId) {
        return deviceMapper.findByPointId(pointId).stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }

    @Override
    public DeviceDTO getDeviceById(Long id) {
        Device device = deviceMapper.selectById(id);
        return device != null ? toDTO(device) : null;
    }

    @Override
    public DeviceDTO getDeviceByDeviceCode(String deviceCode) {
        Device device = deviceMapper.findByDeviceCode(deviceCode);
        return device != null ? toDTO(device) : null;
    }

    @Override
    @Transactional
    public DeviceDTO createDevice(DeviceDTO.CreateRequest request) {
        if (deviceMapper.existsByDeviceCode(request.getDeviceCode())) {
            throw new DuplicateResourceException("设备编码", request.getDeviceCode());
        }

        Device device = new Device();
        device.setPointId(request.getPointId());
        device.setDeviceCode(request.getDeviceCode());
        device.setDeviceName(request.getDeviceName());
        device.setDeviceType(request.getDeviceType());
        device.setDeviceModel(request.getDeviceModel());
        device.setManufacturer(request.getManufacturer());
        device.setStatus(0);

        deviceMapper.insert(device);
        return toDTO(device);
    }

    @Override
    @Transactional
    public DeviceDTO updateDeviceStatus(String deviceCode, Integer status) {
        Device device = deviceMapper.findByDeviceCode(deviceCode);
        if (device == null) {
            throw new ResourceNotFoundException("设备", deviceCode);
        }

        device.setStatus(status);
        deviceMapper.updateById(device);
        return toDTO(device);
    }

    @Override
    @Transactional
    public DeviceDTO controlDevice(String deviceCode, String command) {
        Device device = deviceMapper.findByDeviceCode(deviceCode);
        if (device == null) {
            throw new ResourceNotFoundException("设备", deviceCode);
        }

        switch (command.toLowerCase()) {
            case "on":
                device.setStatus(2);
                log.info("设备 {} 开启", deviceCode);
                break;
            case "off":
                device.setStatus(1);
                log.info("设备 {} 关闭", deviceCode);
                break;
            default:
                log.warn("未知命令: {}", command);
        }

        deviceMapper.updateById(device);
        return toDTO(device);
    }

    @Override
    @Transactional
    public void deleteDevice(Long id) {
        deviceMapper.deleteById(id);
    }

    private DeviceDTO toDTO(Device device) {
        DeviceDTO dto = new DeviceDTO();
        dto.setId(device.getId());
        dto.setPointId(device.getPointId());
        dto.setDeviceCode(device.getDeviceCode());
        dto.setDeviceName(device.getDeviceName());
        dto.setDeviceType(device.getDeviceType());
        dto.setDeviceModel(device.getDeviceModel());
        dto.setManufacturer(device.getManufacturer());
        dto.setStatus(device.getStatus());
        dto.setLastHeartbeat(device.getLastHeartbeat());
        dto.setInstalledAt(device.getInstalledAt());
        dto.setCreatedAt(device.getCreatedAt());
        dto.setUpdatedAt(device.getUpdatedAt());
        return dto;
    }
}

