180	        riskFactor = clamp(riskFactor, new BigDecimal("0.75"), new BigDecimal("1.45"));
181	        BigDecimal waterAmount = baseWaterAmount.multiply(riskFactor);
182	        waterAmount = clamp(waterAmount, new BigDecimal("0.5"), new BigDecimal("45"));
183	
184	        int rawDuration = waterAmount.divide(WATER_PER_SECOND, 0, RoundingMode.HALF_UP).intValue();
185	        int durationSeconds = clamp(rawDuration, MIN_AUTO_DURATION_SEC, MAX_AUTO_DURATION_SEC);
186	
187	        plan.setShouldIrrigate(true);
188	        plan.setWaterAmountL(waterAmount.setScale(1, RoundingMode.HALF_UP));
189	        plan.setDurationSeconds(durationSeconds);
190	        plan.setTargetMoisture(targetMoisture.setScale(1, RoundingMode.HALF_UP));
191	        plan.setMoistureGap(moistureGap.setScale(1, RoundingMode.HALF_UP));
192	        plan.setRiskFactor(riskFactor.setScale(2, RoundingMode.HALF_UP));
193	        plan.setReason("根据环境和门槛自动计划");
194	        return plan;
195	    }
196	
197	    /**
198	     * Plan-only API for clients.
199	     */
200	    public AutoIrrigationPlanResponse buildAutoPlan(IrrigationPlanRequest request) {
201	        Long pointId = request != null ? request.getPointId() : null;
202	        EnvironmentDataDTO envData = request != null ? request.getEnvData() : null;
203	        IrrigationPlanConfig config = request != null ? request.getConfig() : null;
204	
205	        if (pointId == null) {
206	            pointId = 1L;
207	        }
208	        return buildAutoPlan(envData, config);
209	    }
210	
211	    /**
212	     *如果配置和时间规则允许，计算计划并开始灌溉
213	     */
214	    @Transactional
215	    public AutoIrrigationResultResponse startAutoIrrigation(AutoIrrigationRequest request) {
216	        Long pointId = request != null ? request.getPointId() : null;
217	        EnvironmentDataDTO envData = request != null ? request.getEnvData() : null;
218	        IrrigationPlanConfig config = request != null ? request.getConfig() : null;
219	
220	        if (pointId == null) {
221	            pointId = 1L;
222	        }
223	
224	        AutoIrrigationPlanResponse plan = buildAutoPlan(envData, config);
225	
226	        if (config == null || config.getAutoMode() == null || !config.getAutoMode()) {
227	            plan.setShouldIrrigate(false);
228	            plan.setReason("自动模式已禁用");
229	        }
230	
231	        if (plan.isShouldIrrigate() && isCurrentlyIrrigating(pointId)) {
232	            plan.setShouldIrrigate(false);
233	            plan.setReason("灌溉系统已经开始运行");
234	        }
235	
236	        if (plan.isShouldIrrigate()) {
237	            int minInterval = config != null && config.getMinInterval() != null ? config.getMinInterval() : 0;
238	            if (!isAutoIntervalOk(pointId, minInterval)) {
239	                plan.setShouldIrrigate(false);
240	                plan.setReason("最短间隔尚未过去");
241	            }
242	        }
243	
244	        AutoIrrigationResultResponse result = new AutoIrrigationResultResponse();
245	        result.setPlan(plan);
246	
247	        if (plan.isShouldIrrigate()) {
248	            IrrigationLog logEntity = startIrrigationInternal(pointId, plan.getDurationSeconds(), 0);
249	            result.setLog(toDTO(logEntity));
250	            result.setStarted(true);
251	        } else {
252	            result.setStarted(false);
253	            result.setLog(null);
254	        }
255	
256	        return result;
257	    }
258	
259	    private IrrigationLog startIrrigationInternal(Long pointId, Integer duration, Integer mode) {
260	        IrrigationLog irrigationLog = new IrrigationLog();
261	        irrigationLog.setPointId(pointId);
262	        irrigationLog.setDuration(duration);
263	        irrigationLog.setMode(mode);
264	        irrigationLog.setStartTime(LocalDateTime.now());
265	
266	        BigDecimal waterAmount = WATER_PER_SECOND.multiply(new BigDecimal(duration));
267	        irrigationLog.setWaterAmount(waterAmount);
268	
269	        irrigationLogMapper.insert(irrigationLog);
270	        log.info("灌溉开始： pointId={}， durationSec={}， waterAmountL={}， mode={}",
271	                pointId, duration, waterAmount, mode);
272	        return irrigationLog;
273	    }
274	
275	    private boolean isCurrentlyIrrigating(Long pointId) {
276	        IrrigationLog active = irrigationLogMapper.findActiveByPointId(pointId);
277	        return active != null;
278	    }
279	
280	    private boolean isAutoIntervalOk(Long pointId, int minIntervalSeconds) {
281	        if (minIntervalSeconds <= 0) {
282	            return true;
283	        }
284	
285	        IrrigationLog lastAuto = irrigationLogMapper.findLastAutoByPointId(pointId);
286	        if (lastAuto == null || lastAuto.getStartTime() == null) {
287	            return true;
288	        }
289	
290	        Duration elapsed = Duration.between(lastAuto.getStartTime(), LocalDateTime.now());
291	        return elapsed.getSeconds() >= minIntervalSeconds;
292	    }
293	
294	    private AutoIrrigationPlanResponse buildNoIrrigationPlan(int targetMoisture, String reason) {
295	        AutoIrrigationPlanResponse plan = new AutoIrrigationPlanResponse();
296	        plan.setShouldIrrigate(false);
297	        plan.setWaterAmountL(BigDecimal.ZERO);
298	        plan.setDurationSeconds(0);
299	        plan.setTargetMoisture(new BigDecimal(targetMoisture).setScale(1, RoundingMode.HALF_UP));
300	        plan.setMoistureGap(BigDecimal.ZERO);
301	        plan.setRiskFactor(BigDecimal.ONE);
302	        plan.setReason(reason);
303	        return plan;
304	    }
305	
306	    private int clamp(int value, int min, int max) {
307	        return Math.max(min, Math.min(max, value));
308	    }
309	
310	    private BigDecimal clamp(BigDecimal value, BigDecimal min, BigDecimal max) {
311	        if (value.compareTo(min) < 0) {
312	            return min;
313	        }
314	        if (value.compareTo(max) > 0) {
315	            return max;
316	        }
317	        return value;
318	    }
319	
320	    private IrrigationDTO toDTO(IrrigationLog irrigationLog) {
321	        IrrigationDTO dto = new IrrigationDTO();
322	        dto.setId(irrigationLog.getId());
323	        dto.setPointId(irrigationLog.getPointId());
324	        dto.setWaterAmount(irrigationLog.getWaterAmount());
325	        dto.setDuration(irrigationLog.getDuration());
326	        dto.setMode(irrigationLog.getMode());
327	        dto.setStartTime(irrigationLog.getStartTime());
328	        dto.setEndTime(irrigationLog.getEndTime());
329	        dto.setCreatedAt(irrigationLog.getCreatedAt());
330	        return dto;
331	    }
332	}
