211	    private List<WeatherDTO.ForecastDTO> fetchForecast(String locationId) {
212	        try {
213	            String forecastUrl = UriComponentsBuilder.newInstance()
214	                    .scheme("https")
215	                    .host(apiHost)
216	                    .path("/v7/weather/3d")
217	                    .queryParam("location", locationId)
218	                    .queryParam("key", apiKey)
