229	            List<WeatherDTO.ForecastDTO> forecast = new ArrayList<>();
230	            JsonNode daily = root.path("daily");
231	            for (int i = 0; i < Math.min(3, daily.size()); i++) {
232	                JsonNode day = daily.get(i);
