88	        data.setPointId(dto.getPointId());
89	        data.setTemperature(dto.getTemperature());
90	        data.setHumidity(dto.getHumidity());
91	        data.setLight(dto.getLight());
92	        data.setCo2(dto.getCo2());
93	        data.setSoilMoisture(dto.getSoilMoisture());
94	        data.setRecordedAt(dto.getRecordedAt() != null ? dto.getRecordedAt() : LocalDateTime.now());
95	
