package com.agriculture.service.impl;

import com.agriculture.model.dto.EnvironmentDataDTO;
import com.agriculture.entity.Alarm;
import com.agriculture.entity.SensorData;
import com.agriculture.mapper.AlarmMapper;
import com.agriculture.mapper.SensorDataMapper;
import com.agriculture.service.EnvironmentCacheService;
import com.agriculture.service.SensorDataService;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class SensorDataServiceImpl implements SensorDataService {

    private final SensorDataMapper sensorDataMapper;
    private final AlarmMapper alarmMapper;
    private final EnvironmentCacheService environmentCacheService;

    private static final BigDecimal TEMP_MIN = new BigDecimal("10");
    private static final BigDecimal TEMP_MAX = new BigDecimal("35");
    private static final BigDecimal HUMIDITY_MIN = new BigDecimal("30");
    private static final BigDecimal HUMIDITY_MAX = new BigDecimal("80");
    private static final BigDecimal LIGHT_MIN = new BigDecimal("300");
    private static final BigDecimal CO2_MAX = new BigDecimal("1000");
    private static final BigDecimal SOIL_MOISTURE_MIN = new BigDecimal("40");

    @Override
    public EnvironmentDataDTO getCurrentData(Long pointId) {
        EnvironmentDataDTO cached = environmentCacheService.get(pointId);
        if (cached != null) {
            return cached;
        }

        SensorData data = sensorDataMapper.findFirstByPointIdOrderByRecordedAtDesc(pointId);
        if (data == null) {
            return null;
        }

        EnvironmentDataDTO dto = toDTO(data);
        environmentCacheService.put(pointId, dto);
        return dto;
    }

    @Override
    public List<EnvironmentDataDTO> getHistoryData(Long pointId, int limit) {
        Page<SensorData> page = new Page<>(1, limit);
        LambdaQueryWrapper<SensorData> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SensorData::getPointId, pointId)
                .orderByDesc(SensorData::getRecordedAt);
        return sensorDataMapper.selectPage(page, wrapper).getRecords().stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }

    @Override
    public Page<EnvironmentDataDTO> getHistoryDataPaged(Long pointId, int pageNum, int pageSize) {
        Page<SensorData> page = new Page<>(pageNum + 1, pageSize);
        LambdaQueryWrapper<SensorData> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(SensorData::getPointId, pointId)
                .orderByDesc(SensorData::getRecordedAt);
        Page<SensorData> dataPage = sensorDataMapper.selectPage(page, wrapper);

        Page<EnvironmentDataDTO> dtoPage = new Page<>(pageNum + 1, pageSize);
        dtoPage.setTotal(dataPage.getTotal());
        dtoPage.setRecords(dataPage.getRecords().stream().map(this::toDTO).collect(Collectors.toList()));
        return dtoPage;
    }

    @Override
    public List<EnvironmentDataDTO> getHistoryDataByTimeRange(Long pointId, LocalDateTime startTime, LocalDateTime endTime) {
        return sensorDataMapper.findByPointIdAndTimeRange(pointId, startTime, endTime).stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }

    @Override
    @Transactional
    public EnvironmentDataDTO saveData(EnvironmentDataDTO dto) {
        SensorData data = new SensorData();
        data.setPointId(dto.getPointId());
        data.setTemperature(dto.getTemperature());
        data.setHumidity(dto.getHumidity());
        data.setLight(dto.getLight());
        data.setCo2(dto.getCo2());
        data.setSoilMoisture(dto.getSoilMoisture());
        data.setRecordedAt(dto.getRecordedAt() != null ? dto.getRecordedAt() : LocalDateTime.now());

        sensorDataMapper.insert(data);
        checkAndCreateAlarms(data);

        EnvironmentDataDTO saved = toDTO(data);
        environmentCacheService.put(data.getPointId(), saved);
        return saved;
    }

    private void checkAndCreateAlarms(SensorData data) {
        Long pointId = data.getPointId();

        Set<String> existingUnprocessedTypes = new HashSet<>(alarmMapper.findUnprocessedAlarmTypesByPointId(pointId));
        List<Alarm> alarmsToCreate = new ArrayList<>();

        if (data.getTemperature() != null) {
            if (data.getTemperature().compareTo(TEMP_MAX) > 0) {
                addAlarmIfNeeded(pointId, "TEMPERATURE_HIGH", data.getTemperature(), TEMP_MAX, existingUnprocessedTypes, alarmsToCreate);
            } else if (data.getTemperature().compareTo(TEMP_MIN) < 0) {
                addAlarmIfNeeded(pointId, "TEMPERATURE_LOW", data.getTemperature(), TEMP_MIN, existingUnprocessedTypes, alarmsToCreate);
            }
        }

        if (data.getHumidity() != null) {
            if (data.getHumidity().compareTo(HUMIDITY_MAX) > 0) {
                addAlarmIfNeeded(pointId, "HUMIDITY_HIGH", data.getHumidity(), HUMIDITY_MAX, existingUnprocessedTypes, alarmsToCreate);
            } else if (data.getHumidity().compareTo(HUMIDITY_MIN) < 0) {
                addAlarmIfNeeded(pointId, "HUMIDITY_LOW", data.getHumidity(), HUMIDITY_MIN, existingUnprocessedTypes, alarmsToCreate);
            }
        }

        if (data.getLight() != null && data.getLight().compareTo(LIGHT_MIN) < 0) {
            addAlarmIfNeeded(pointId, "LIGHT_LOW", data.getLight(), LIGHT_MIN, existingUnprocessedTypes, alarmsToCreate);
        }

        if (data.getCo2() != null && data.getCo2().compareTo(CO2_MAX) > 0) {
            addAlarmIfNeeded(pointId, "CO2_HIGH", data.getCo2(), CO2_MAX, existingUnprocessedTypes, alarmsToCreate);
        }

        if (data.getSoilMoisture() != null && data.getSoilMoisture().compareTo(SOIL_MOISTURE_MIN) < 0) {
            addAlarmIfNeeded(pointId, "SOIL_MOISTURE_LOW", data.getSoilMoisture(), SOIL_MOISTURE_MIN, existingUnprocessedTypes, alarmsToCreate);
        }

        for (Alarm alarm : alarmsToCreate) {
            alarmMapper.insert(alarm);
            log.warn("创建报警: 检测点={}, 类型={}, 值={}, 阈值={}",
                    alarm.getPointId(), alarm.getAlarmType(), alarm.getAlarmValue(), alarm.getThreshold());
        }
    }

    private void addAlarmIfNeeded(Long pointId, String alarmType, BigDecimal alarmValue, BigDecimal threshold,
                                  Set<String> existingUnprocessedTypes, List<Alarm> alarmsToCreate) {
        if (existingUnprocessedTypes.contains(alarmType)) {
            return;
        }

        Alarm alarm = new Alarm();
        alarm.setPointId(pointId);
        alarm.setAlarmType(alarmType);
        alarm.setAlarmValue(alarmValue);
        alarm.setThreshold(threshold);
        alarm.setStatus(0);

        alarmsToCreate.add(alarm);
        existingUnprocessedTypes.add(alarmType);
    }

    @Override
    @Transactional
    public void cleanOldData(int daysToKeep) {
        LocalDateTime cutoffTime = LocalDateTime.now().minusDays(daysToKeep);
        sensorDataMapper.deleteByRecordedAtBefore(cutoffTime);
        log.info("清理{}天前的传感器数据", daysToKeep);
    }

    private EnvironmentDataDTO toDTO(SensorData data) {
        EnvironmentDataDTO dto = new EnvironmentDataDTO();
        dto.setId(data.getId());
        dto.setPointId(data.getPointId());
        dto.setTemperature(data.getTemperature());
        dto.setHumidity(data.getHumidity());
        dto.setLight(data.getLight());
        dto.setCo2(data.getCo2());
        dto.setSoilMoisture(data.getSoilMoisture());
        dto.setRecordedAt(data.getRecordedAt());
        dto.setCreatedAt(data.getCreatedAt());
        return dto;
    }
}

package com.agriculture.service.impl;

import com.agriculture.common.exception.InvalidOperationException;
import com.agriculture.common.exception.ResourceNotFoundException;
import com.agriculture.model.response.AutoIrrigationPlanResponse;
import com.agriculture.model.request.AutoIrrigationRequest;
import com.agriculture.model.response.AutoIrrigationResultResponse;
import com.agriculture.model.dto.EnvironmentDataDTO;
import com.agriculture.model.dto.IrrigationDTO;
import com.agriculture.model.request.IrrigationPlanConfig;
import com.agriculture.model.request.IrrigationPlanRequest;
import com.agriculture.entity.IrrigationLog;
import com.agriculture.mapper.IrrigationLogMapper;
import com.agriculture.service.IrrigationService;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.Duration;
import java.time.LocalDateTime;
import java.util.List;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class IrrigationServiceImpl implements IrrigationService {

    private final IrrigationLogMapper irrigationLogMapper;

    private static final BigDecimal WATER_PER_SECOND = new BigDecimal("0.5");
    private static final BigDecimal SOIL_MOISTURE_GAIN_PER_LITER = new BigDecimal("1.6666667");
    private static final int MIN_AUTO_DURATION_SEC = 10;
    private static final int MAX_AUTO_DURATION_SEC = 180;

    @Override
    public List<IrrigationDTO> getLogsByPointId(Long pointId) {
        return irrigationLogMapper.findByPointIdOrderByStartTimeDesc(pointId).stream()
                .map(this::toDTO)
                .collect(Collectors.toList());
    }

    @Override
    public Page<IrrigationDTO> getLogsPaged(Long pointId, int pageNum, int pageSize) {
        Page<IrrigationLog> page = new Page<>(pageNum + 1, pageSize);
        LambdaQueryWrapper<IrrigationLog> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(IrrigationLog::getPointId, pointId)
               .orderByDesc(IrrigationLog::getStartTime);
        Page<IrrigationLog> logPage = irrigationLogMapper.selectPage(page, wrapper);

        Page<IrrigationDTO> dtoPage = new Page<>(pageNum + 1, pageSize);
        dtoPage.setTotal(logPage.getTotal());
        dtoPage.setRecords(logPage.getRecords().stream().map(this::toDTO).collect(Collectors.toList()));
        return dtoPage;
    }

    @Override
    public IrrigationDTO getLatestLog(Long pointId) {
        IrrigationLog log = irrigationLogMapper.findFirstByPointIdOrderByStartTimeDesc(pointId);
        return log != null ? toDTO(log) : null;
    }

    @Override
    public Double getTotalWaterAmount(Long pointId) {
        return irrigationLogMapper.sumWaterAmountByPointId(pointId);
    }

    @Override
    @Transactional
    public IrrigationDTO startIrrigation(IrrigationDTO.StartRequest request) {
        IrrigationLog irrigationLog = startIrrigationInternal(
                request.getPointId(),
                request.getDuration(),
                request.getMode()
        );
        return toDTO(irrigationLog);
    }

    @Override
    @Transactional
    public IrrigationDTO stopIrrigation(Long logId) {
        IrrigationLog irrigationLog = irrigationLogMapper.selectById(logId);
        if (irrigationLog == null) {
            throw new ResourceNotFoundException("灌溉日志", logId);
        }

        if (irrigationLog.getEndTime() != null) {
            throw new InvalidOperationException("灌溉已经停止");
        }

        irrigationLog.setEndTime(LocalDateTime.now());

        if (irrigationLog.getStartTime() != null) {
            Duration duration = Duration.between(irrigationLog.getStartTime(), irrigationLog.getEndTime());
            int actualDuration = (int) duration.getSeconds();
            irrigationLog.setDuration(actualDuration);

            BigDecimal actualWaterAmount = WATER_PER_SECOND.multiply(new BigDecimal(actualDuration));
            irrigationLog.setWaterAmount(actualWaterAmount);
        }

        irrigationLogMapper.updateById(irrigationLog);
        log.info("灌溉停止：logId={}， durationSec={}， waterAmountL={}",
                logId, irrigationLog.getDuration(), irrigationLog.getWaterAmount());

        return toDTO(irrigationLog);
    }

    @Override
    @Transactional
    public void deleteLog(Long id) {
        irrigationLogMapper.deleteById(id);
    }

    @Override
    public AutoIrrigationPlanResponse buildAutoPlan(EnvironmentDataDTO envData, IrrigationPlanConfig config) {
        AutoIrrigationPlanResponse plan = new AutoIrrigationPlanResponse();

        if (envData == null || envData.getSoilMoisture() == null) {
            plan.setShouldIrrigate(false);
            plan.setWaterAmountL(BigDecimal.ZERO);
            plan.setDurationSeconds(0);
            plan.setTargetMoisture(BigDecimal.ZERO);
            plan.setMoistureGap(BigDecimal.ZERO);
            plan.setRiskFactor(BigDecimal.ONE);
            plan.setReason("缺少环境数据");
            return plan;
        }

        int threshold = 40;
        if (config != null && config.getMoistureThreshold() != null) {
            threshold = clamp(config.getMoistureThreshold(), 20, 70);
        }

        BigDecimal soilMoisture = clamp(envData.getSoilMoisture(), BigDecimal.ZERO, new BigDecimal("100"));
        if (soilMoisture.compareTo(new BigDecimal(threshold)) >= 0) {
            return buildNoIrrigationPlan(threshold, "土壤水分超过阈值");
        }

        BigDecimal targetMoisture = new BigDecimal(threshold + 12).min(new BigDecimal("75"));
        BigDecimal moistureGap = targetMoisture.subtract(soilMoisture).max(BigDecimal.ZERO);

        BigDecimal baseWaterAmount = moistureGap.divide(SOIL_MOISTURE_GAIN_PER_LITER, 6, RoundingMode.HALF_UP);
        BigDecimal riskFactor = BigDecimal.ONE;

        if (envData.getTemperature() != null) {
            if (envData.getTemperature().compareTo(new BigDecimal("35")) > 0) {
                riskFactor = riskFactor.add(new BigDecimal("0.2"));
            } else if (envData.getTemperature().compareTo(new BigDecimal("30")) > 0) {
                riskFactor = riskFactor.add(new BigDecimal("0.1"));
            } else if (envData.getTemperature().compareTo(new BigDecimal("15")) < 0) {
                riskFactor = riskFactor.subtract(new BigDecimal("0.08"));
            }
        }

        if (envData.getHumidity() != null) {
            if (envData.getHumidity().compareTo(new BigDecimal("40")) < 0) {
                riskFactor = riskFactor.add(new BigDecimal("0.1"));
            } else if (envData.getHumidity().compareTo(new BigDecimal("75")) > 0) {
                riskFactor = riskFactor.subtract(new BigDecimal("0.08"));
            }
        }

        if (envData.getLight() != null) {
            if (envData.getLight().compareTo(new BigDecimal("30000")) > 0) {
                riskFactor = riskFactor.add(new BigDecimal("0.15"));
            } else if (envData.getLight().compareTo(new BigDecimal("15000")) > 0) {
                riskFactor = riskFactor.add(new BigDecimal("0.08"));
            } else if (envData.getLight().compareTo(new BigDecimal("1000")) < 0) {
                riskFactor = riskFactor.subtract(new BigDecimal("0.05"));
            }
        }

        if (envData.getCo2() != null && envData.getCo2().compareTo(new BigDecimal("1000")) > 0) {
            riskFactor = riskFactor.add(new BigDecimal("0.05"));
        }

        riskFactor = clamp(riskFactor, new BigDecimal("0.75"), new BigDecimal("1.45"));
        BigDecimal waterAmount = baseWaterAmount.multiply(riskFactor);
        waterAmount = clamp(waterAmount, new BigDecimal("0.5"), new BigDecimal("45"));

        int rawDuration = waterAmount.divide(WATER_PER_SECOND, 0, RoundingMode.HALF_UP).intValue();
        int durationSeconds = clamp(rawDuration, MIN_AUTO_DURATION_SEC, MAX_AUTO_DURATION_SEC);

        plan.setShouldIrrigate(true);
        plan.setWaterAmountL(waterAmount.setScale(1, RoundingMode.HALF_UP));
        plan.setDurationSeconds(durationSeconds);
        plan.setTargetMoisture(targetMoisture.setScale(1, RoundingMode.HALF_UP));
        plan.setMoistureGap(moistureGap.setScale(1, RoundingMode.HALF_UP));
        plan.setRiskFactor(riskFactor.setScale(2, RoundingMode.HALF_UP));
        plan.setReason("根据环境和门槛自动计划");
        return plan;
    }

    @Override
    public AutoIrrigationPlanResponse buildAutoPlan(IrrigationPlanRequest request) {
        EnvironmentDataDTO envData = request != null ? request.getEnvData() : null;
        IrrigationPlanConfig config = request != null ? request.getConfig() : null;
        return buildAutoPlan(envData, config);
    }

    @Override
    @Transactional
    public AutoIrrigationResultResponse startAutoIrrigation(AutoIrrigationRequest request) {
        Long pointId = request != null ? request.getPointId() : null;
        EnvironmentDataDTO envData = request != null ? request.getEnvData() : null;
        IrrigationPlanConfig config = request != null ? request.getConfig() : null;

        if (pointId == null) {
            pointId = 1L;
        }

        AutoIrrigationPlanResponse plan = buildAutoPlan(envData, config);

        if (config == null || config.getAutoMode() == null || !config.getAutoMode()) {
            plan.setShouldIrrigate(false);
            plan.setReason("自动模式已禁用");
        }

        if (plan.isShouldIrrigate() && isCurrentlyIrrigating(pointId)) {
            plan.setShouldIrrigate(false);
            plan.setReason("灌溉系统已经开始运行");
        }

        if (plan.isShouldIrrigate()) {
            int minInterval = config != null && config.getMinInterval() != null ? config.getMinInterval() : 0;
            if (!isAutoIntervalOk(pointId, minInterval)) {
                plan.setShouldIrrigate(false);
                plan.setReason("最短间隔尚未过去");
            }
        }

        AutoIrrigationResultResponse result = new AutoIrrigationResultResponse();
        result.setPlan(plan);

        if (plan.isShouldIrrigate()) {
            IrrigationLog logEntity = startIrrigationInternal(pointId, plan.getDurationSeconds(), 0);
            result.setLog(toDTO(logEntity));
            result.setStarted(true);
        } else {
            result.setStarted(false);
            result.setLog(null);
        }

        return result;
    }

    private IrrigationLog startIrrigationInternal(Long pointId, Integer duration, Integer mode) {
        IrrigationLog irrigationLog = new IrrigationLog();
        irrigationLog.setPointId(pointId);
        irrigationLog.setDuration(duration);
        irrigationLog.setMode(mode);
        irrigationLog.setStartTime(LocalDateTime.now());

        BigDecimal waterAmount = WATER_PER_SECOND.multiply(new BigDecimal(duration));
        irrigationLog.setWaterAmount(waterAmount);

        irrigationLogMapper.insert(irrigationLog);
        log.info("灌溉开始： pointId={}， durationSec={}， waterAmountL={}， mode={}",
                pointId, duration, waterAmount, mode);
        return irrigationLog;
    }

    private boolean isCurrentlyIrrigating(Long pointId) {
        IrrigationLog active = irrigationLogMapper.findActiveByPointId(pointId);
        return active != null;
    }

    private boolean isAutoIntervalOk(Long pointId, int minIntervalSeconds) {
        if (minIntervalSeconds <= 0) {
            return true;
        }

        IrrigationLog lastAuto = irrigationLogMapper.findLastAutoByPointId(pointId);
        if (lastAuto == null || lastAuto.getStartTime() == null) {
            return true;
        }

        Duration elapsed = Duration.between(lastAuto.getStartTime(), LocalDateTime.now());
        return elapsed.getSeconds() >= minIntervalSeconds;
    }

    private AutoIrrigationPlanResponse buildNoIrrigationPlan(int targetMoisture, String reason) {
        AutoIrrigationPlanResponse plan = new AutoIrrigationPlanResponse();
        plan.setShouldIrrigate(false);
        plan.setWaterAmountL(BigDecimal.ZERO);
        plan.setDurationSeconds(0);
        plan.setTargetMoisture(new BigDecimal(targetMoisture).setScale(1, RoundingMode.HALF_UP));
        plan.setMoistureGap(BigDecimal.ZERO);
        plan.setRiskFactor(BigDecimal.ONE);
        plan.setReason(reason);
        return plan;
    }

    private int clamp(int value, int min, int max) {
        return Math.max(min, Math.min(max, value));
    }

    private BigDecimal clamp(BigDecimal value, BigDecimal min, BigDecimal max) {
        if (value.compareTo(min) < 0) return min;
        if (value.compareTo(max) > 0) return max;
        return value;
    }

    private IrrigationDTO toDTO(IrrigationLog irrigationLog) {
        IrrigationDTO dto = new IrrigationDTO();
        dto.setId(irrigationLog.getId());
        dto.setPointId(irrigationLog.getPointId());
        dto.setWaterAmount(irrigationLog.getWaterAmount());
        dto.setDuration(irrigationLog.getDuration());
        dto.setMode(irrigationLog.getMode());
        dto.setStartTime(irrigationLog.getStartTime());
        dto.setEndTime(irrigationLog.getEndTime());
        dto.setCreatedAt(irrigationLog.getCreatedAt());
        return dto;
    }
}

package com.agriculture.service.impl;

import com.agriculture.common.exception.BusinessException;
import com.agriculture.model.dto.WeatherDTO;
import com.agriculture.service.WeatherService;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.cache.annotation.Cacheable;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;
import org.springframework.web.util.UriComponentsBuilder;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;

@Service
@Slf4j
public class WeatherServiceImpl implements WeatherService {

    @Value("${weather.qweather.api-key:}")
    private String apiKey;

    @Value("${weather.qweather.api-host:devapi.qweather.com}")
    private String apiHost;

    @Value("${weather.qweather.geo-host:geoapi.qweather.com}")
    private String geoApiHost;

    private final RestTemplate restTemplate = new RestTemplate();
    private final ObjectMapper objectMapper = new ObjectMapper();

    @Override
    @Cacheable(value = "weather", key = "#latitude.toString() + '_' + #longitude.toString()", unless = "#result == null")
    public WeatherDTO getWeatherByLocation(Double latitude, Double longitude) {
        checkApiKey();

        try {
            String locationId = getLocationIdByCoords(latitude, longitude);
            if (locationId == null) {
                throw new BusinessException(502, "无法识别该位置");
            }

            log.info("位置查询成功: 经纬度 ({}, {}) -> 城市ID {}", latitude, longitude, locationId);
            return fetchWeatherByLocationId(locationId, latitude, longitude);
        } catch (BusinessException e) {
            throw e;
        } catch (Exception e) {
            log.error("获取天气失败", e);
            throw new BusinessException(502, "获取天气失败: " + e.getMessage());
        }
    }

    private void checkApiKey() {
        if (apiKey == null || apiKey.isEmpty()) {
            throw new BusinessException(500, "天气服务未配置API Key，请联系管理员配置和风天气API");
        }
    }

    private String getLocationIdByCoords(Double latitude, Double longitude) {
        try {
            String location = String.format("%.2f,%.2f", longitude, latitude);

            String url = UriComponentsBuilder.newInstance()
                    .scheme("https")
                    .path("geo/v2/city/lookup")
                    .queryParam("location", location)
                    .queryParam("key", apiKey)
                    .build()
                    .toUriString();

            log.info("请求城市查询: {}", url);
            String response = restTemplate.getForObject(url, String.class);
            JsonNode root = objectMapper.readTree(response);

            String code = root.path("code").asText();
            if (!"200".equals(code)) {
                log.error("城市查询失败: code={}", code);
                return null;
            }

            JsonNode locationNode = root.path("location");
            if (locationNode.isArray() && locationNode.size() > 0) {
                JsonNode first = locationNode.get(0);
                return first.path("id").asText();
            }

            return null;
        } catch (Exception e) {
            log.error("城市查询请求失败", e);
            return null;
        }
    }

    private WeatherDTO fetchWeatherByLocationId(String locationId, Double latitude, Double longitude) {
        try {
            String nowUrl = UriComponentsBuilder.newInstance()
                    .scheme("https")
                    .host(apiHost)
                    .path("/v7/weather/now")
                    .queryParam("location", locationId)
                    .queryParam("key", apiKey)
                    .build()
                    .toUriString();

            String nowResponse = restTemplate.getForObject(nowUrl, String.class);
            JsonNode nowRoot = objectMapper.readTree(nowResponse);
            String code = nowRoot.path("code").asText();

            if (!"200".equals(code)) {
                log.error("天气API返回错误: {}", code);
                throw new BusinessException(502, "天气API错误: " + code);
            }

            JsonNode now = nowRoot.path("now");
            WeatherDTO weather = new WeatherDTO();
            weather.setTemp(parseDouble(now.path("temp").asText()));
            weather.setFeelsLike(parseDouble(now.path("feelsLike").asText()));
            weather.setText(now.path("text").asText());
            weather.setIcon(now.path("icon").asText());
            weather.setHumidity(parseInt(now.path("humidity").asText()));
            weather.setWindDir(now.path("windDir").asText());
            weather.setWindSpeed(parseDouble(now.path("windSpeed").asText()));
            weather.setPressure(parseInt(now.path("pressure").asText()));
            weather.setVisibility(parseDouble(now.path("vis").asText()));
            weather.setUpdateTime(now.path("obsTime").asText());

            weather.setLocationId(locationId);
            weather.setLatitude(latitude);
            weather.setLongitude(longitude);

            LocationInfo locInfo = getCityName(locationId);
            if (locInfo != null) {
                weather.setLocation(locInfo.getName());
                weather.setCity(locInfo.getCity());
                weather.setProvince(locInfo.getProvince());
            }

            weather.setForecast(fetchForecast(locationId));
            return weather;
        } catch (BusinessException e) {
            throw e;
        } catch (Exception e) {
            log.error("获取天气数据失败", e);
            throw new BusinessException(502, "获取天气数据失败: " + e.getMessage());
        }
    }

    private LocationInfo getCityName(String locationId) {
        try {
            String url = UriComponentsBuilder.newInstance()
                    .scheme("https")
                    .host(geoApiHost)
                    .path("/v2/city/lookup")
                    .queryParam("location", locationId)
                    .queryParam("key", apiKey)
                    .build()
                    .toUriString();

            String response = restTemplate.getForObject(url, String.class);
            JsonNode root = objectMapper.readTree(response);

            if ("200".equals(root.path("code").asText())) {
                JsonNode locationNode = root.path("location");
                if (locationNode.isArray() && locationNode.size() > 0) {
                    JsonNode first = locationNode.get(0);
                    LocationInfo info = new LocationInfo();
                    info.setName(first.path("name").asText());
                    info.setCity(first.path("name").asText());
                    info.setProvince(first.path("adm1").asText());
                    return info;
                }
            }
        } catch (Exception e) {
            log.warn("获取城市名称失败", e);
        }
        return null;
    }

    private List<WeatherDTO.ForecastDTO> fetchForecast(String locationId) {
        try {
            String forecastUrl = UriComponentsBuilder.newInstance()
                    .scheme("https")
                    .host(apiHost)
                    .path("/v7/weather/3d")
                    .queryParam("location", locationId)
                    .queryParam("key", apiKey)
                    .build()
                    .toUriString();

            String response = restTemplate.getForObject(forecastUrl, String.class);
            JsonNode root = objectMapper.readTree(response);

            if (!"200".equals(root.path("code").asText())) {
                return new ArrayList<>();
            }

            List<WeatherDTO.ForecastDTO> forecast = new ArrayList<>();
            JsonNode daily = root.path("daily");
            for (int i = 0; i < Math.min(3, daily.size()); i++) {
                JsonNode day = daily.get(i);
                WeatherDTO.ForecastDTO dto = new WeatherDTO.ForecastDTO();
                dto.setDate(formatDate(day.path("fxDate").asText()));
                dto.setTempMax(parseInt(day.path("tempMax").asText()));
                dto.setTempMin(parseInt(day.path("tempMin").asText()));
                dto.setTextDay(day.path("textDay").asText());
                dto.setTextNight(day.path("textNight").asText());
                dto.setIconDay(day.path("iconDay").asText());
                dto.setIconNight(day.path("iconNight").asText());
                forecast.add(dto);
            }
            return forecast;
        } catch (Exception e) {
            log.warn("获取天气预报失败", e);
            return new ArrayList<>();
        }
    }

    private Double parseDouble(String value) {
        try { return Double.parseDouble(value); } catch (Exception e) { return 0.0; }
    }

    private Integer parseInt(String value) {
        try { return Integer.parseInt(value); } catch (Exception e) { return 0; }
    }

    private String formatDate(String date) {
        try {
            LocalDate d = LocalDate.parse(date);
            return d.format(DateTimeFormatter.ofPattern("MM-dd"));
        } catch (Exception e) {
            return date;
        }
    }

    private static class LocationInfo {
        private String name;
        private String city;
        private String province;

        public String getName() { return name; }
        public void setName(String name) { this.name = name; }
        public String getCity() { return city; }
        public void setCity(String city) { this.city = city; }
        public String getProvince() { return province; }
        public void setProvince(String province) { this.province = province; }
    }
}

package com.agriculture.service.impl;

import com.agriculture.entity.AiInteraction;
import com.agriculture.mapper.AiInteractionMapper;
import com.agriculture.service.ChatHistoryService;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;

import java.util.List;

@Slf4j
@Service
@RequiredArgsConstructor
public class ChatHistoryServiceImpl implements ChatHistoryService {

    private final AiInteractionMapper aiInteractionMapper;
    private static final String TYPE_CHAT = "chat";

    @Override
    public void saveUserMessage(String sessionId, String content) {
        saveMessage(sessionId, "user", content);
    }

    @Override
    public void saveAssistantMessage(String sessionId, String content) {
        saveMessage(sessionId, "assistant", content);
    }

    @Override
    @Async
    public void saveMessageAsync(String sessionId, String role, String content) {
        saveMessage(sessionId, role, content);
    }

    private void saveMessage(String sessionId, String role, String content) {
        AiInteraction history = new AiInteraction();
        history.setSessionId(sessionId);
        history.setRole(role);
        history.setContent(content);
        history.setInteractionType(TYPE_CHAT);
        aiInteractionMapper.insert(history);
        log.debug("保存对话历史: sessionId={}, role={}", sessionId, role);
    }

    @Override
    public List<AiInteraction> getHistoryBySessionId(String sessionId) {
        return aiInteractionMapper.findBySessionId(sessionId);
    }

    @Override
    public Page<AiInteraction> getHistoryPaged(String sessionId, int pageNum, int pageSize) {
        Page<AiInteraction> page = new Page<>(pageNum + 1, pageSize);
        LambdaQueryWrapper<AiInteraction> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(AiInteraction::getSessionId, sessionId)
                .eq(AiInteraction::getInteractionType, TYPE_CHAT)
                .orderByAsc(AiInteraction::getCreatedAt);
        return aiInteractionMapper.selectPage(page, wrapper);
    }

    @Override
    public List<AiInteraction> getRecentHistory(String sessionId, int limit) {
        LambdaQueryWrapper<AiInteraction> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(AiInteraction::getSessionId, sessionId)
                .eq(AiInteraction::getInteractionType, TYPE_CHAT)
                .orderByDesc(AiInteraction::getCreatedAt)
                .last("LIMIT " + limit);
        return aiInteractionMapper.selectList(wrapper);
    }

    @Override
    public void deleteBySessionId(String sessionId) {
        LambdaQueryWrapper<AiInteraction> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(AiInteraction::getSessionId, sessionId);
        aiInteractionMapper.delete(wrapper);
        log.info("删除会话历史: sessionId={}", sessionId);
    }

    @Override
    public Long countBySessionId(String sessionId) {
        LambdaQueryWrapper<AiInteraction> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(AiInteraction::getSessionId, sessionId)
                .eq(AiInteraction::getInteractionType, TYPE_CHAT);
        return aiInteractionMapper.selectCount(wrapper);
    }
}

