package com.agriculture.service.impl;

import com.agriculture.entity.CropPlanting;
import com.agriculture.entity.CropStageConfig;
import com.agriculture.mapper.CropPlantingMapper;
import com.agriculture.mapper.CropStageConfigMapper;
import com.agriculture.model.dto.IrrigationStrategyDTO;
import com.agriculture.service.CropStageService;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.temporal.ChronoUnit;
import java.util.List;

@Slf4j
@Service
@RequiredArgsConstructor
public class CropStageServiceImpl implements CropStageService {

    private final CropPlantingMapper cropPlantingMapper;
    private final CropStageConfigMapper stageConfigMapper;

    @Override
    public IrrigationStrategyDTO getStrategy(Long pointId) {
        IrrigationStrategyDTO strategy = new IrrigationStrategyDTO();

        CropPlanting crop = getActiveCropByPointId(pointId);

        if (crop == null) {
            return getDefaultStrategy();
        }

        int daysSincePlanting = calculateDaysSincePlanting(crop.getPlantingDate());

        CropStageConfig stage = getStageConfigByCropCodeAndDay(
                crop.getCropCode(), daysSincePlanting);

        if (stage == null) {
            log.warn("未找到作物阶段配置: cropCode={}, days={}", crop.getCropCode(), daysSincePlanting);
            return getDefaultStrategy();
        }

        strategy.setHasCropConfig(true);
        strategy.setCropCode(crop.getCropCode());
        strategy.setCropName(crop.getCropName());
        strategy.setCurrentStage(stage.getStageName());
        strategy.setDaysSincePlanting(daysSincePlanting);
        strategy.setMinHumidity(stage.getMinHumidity());
        strategy.setMaxHumidity(stage.getMaxHumidity());
        strategy.setOptimalHumidity(stage.getOptimalHumidity());
        strategy.setIrrigationFactor(stage.getIrrigationFactor());
        strategy.setFrequencyHint(stage.getFrequencyHint());
        strategy.setWaterNeeds(stage.getWaterNeeds());
        strategy.setSpecialNotes(stage.getSpecialNotes());

        updateCropStageIfNeeded(crop, stage.getStageCode(), stage.getStageName(), daysSincePlanting);

        return strategy;
    }

    @Override
    public BigDecimal adjustWaterByStage(BigDecimal originalWaterAmount,
                                          IrrigationStrategyDTO strategy,
                                          BigDecimal currentMoisture) {
        if (!strategy.getHasCropConfig()) {
            return originalWaterAmount;
        }

        BigDecimal adjustedWater = originalWaterAmount.multiply(strategy.getIrrigationFactor());

        if (strategy.getMaxHumidity() != null && currentMoisture != null) {
            BigDecimal maxAllowed = strategy.getMaxHumidity();
            if (currentMoisture.compareTo(maxAllowed) >= 0) {
                log.info("当前湿度{}%已达阶段最高限制{}%", currentMoisture, maxAllowed);
                return BigDecimal.ZERO;
            }
        }

        log.debug("调整灌溉量: original={}, factor={}, adjusted={}",
                originalWaterAmount, strategy.getIrrigationFactor(), adjustedWater);

        return adjustedWater;
    }

    @Override
    public List<CropStageConfig> getStageConfigs(String cropCode) {
        LambdaQueryWrapper<CropStageConfig> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(CropStageConfig::getCropCode, cropCode)
               .orderByAsc(CropStageConfig::getStageOrder);
        return stageConfigMapper.selectList(wrapper);
    }

    @Override
    @Transactional
    public void setCrop(Long pointId, String cropCode, String cropName, LocalDate plantingDate) {
        CropPlanting existing = getActiveCropByPointId(pointId);

        if (existing != null) {
            existing.setCropCode(cropCode);
            existing.setCropName(cropName);
            existing.setPlantingDate(plantingDate);
            existing.setCurrentStage(null);
            existing.setStageUpdatedAt(null);
            cropPlantingMapper.updateById(existing);
            log.info("更新作物信息: pointId={}, cropCode={}", pointId, cropCode);
        } else {
            CropPlanting newCrop = new CropPlanting();
            newCrop.setPointId(pointId);
            newCrop.setCropCode(cropCode);
            newCrop.setCropName(cropName);
            newCrop.setPlantingDate(plantingDate);
            newCrop.setStatus(1);
            cropPlantingMapper.insert(newCrop);
            log.info("创建作物信息: pointId={}, cropCode={}", pointId, cropCode);
        }
    }

    @Override
    @Transactional
    public void harvestCrop(Long pointId) {
        CropPlanting crop = getActiveCropByPointId(pointId);
        if (crop != null) {
            crop.setStatus(0);
            cropPlantingMapper.updateById(crop);
            log.info("作物已收获: pointId={}", pointId);
        }
    }

    @Override
    public String[] getSupportedCropCodes() {
        return new String[]{
                "tomato", "cucumber", "pepper", "eggplant",
                "rice", "corn", "vegetable", "strawberry", "watermelon", "cabbage"
        };
    }

    @Override
    public String[] getSupportedCropTypes() {
        return getSupportedCropCodes();
    }

    @Override
    public String getCropName(String cropCode) {
        switch (cropCode) {
            case "tomato": return "番茄";
            case "cucumber": return "黄瓜";
            case "pepper": return "辣椒";
            case "eggplant": return "茄子";
            case "rice": return "水稻";
            case "corn": return "玉米";
            case "vegetable": return "蔬菜";
            case "strawberry": return "草莓";
            case "watermelon": return "西瓜";
            case "cabbage": return "白菜";
            default: return cropCode;
        }
    }

    @Override
    public String getCropTypeName(String cropCode) {
        return getCropName(cropCode);
    }

    private CropPlanting getActiveCropByPointId(Long pointId) {
        LambdaQueryWrapper<CropPlanting> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(CropPlanting::getPointId, pointId)
               .eq(CropPlanting::getStatus, 1);
        return cropPlantingMapper.selectOne(wrapper);
    }

    private CropStageConfig getStageConfigByCropCodeAndDay(String cropCode, int days) {
        LambdaQueryWrapper<CropStageConfig> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(CropStageConfig::getCropCode, cropCode)
               .le(CropStageConfig::getStartDay, days)
               .ge(CropStageConfig::getEndDay, days);
        return stageConfigMapper.selectOne(wrapper);
    }

    private int calculateDaysSincePlanting(LocalDate plantingDate) {
        if (plantingDate == null) return 0;
        return (int) ChronoUnit.DAYS.between(plantingDate, LocalDate.now());
    }

    @Transactional
    protected void updateCropStageIfNeeded(CropPlanting crop, String newStageCode, String newStageName, int currentDay) {
        if (!newStageCode.equals(crop.getCurrentStage())) {
            crop.setCurrentStage(newStageName);
            crop.setCurrentStageDay(currentDay);
            crop.setStageUpdatedAt(LocalDate.now());
            cropPlantingMapper.updateById(crop);
            log.info("更新作物阶段: pointId={}, cropName={}, newStage={}",
                    crop.getPointId(), crop.getCropName(), newStageName);
        }
    }

    private IrrigationStrategyDTO getDefaultStrategy() {
        IrrigationStrategyDTO strategy = new IrrigationStrategyDTO();
        strategy.setHasCropConfig(false);
        strategy.setMinHumidity(new BigDecimal("40"));
        strategy.setMaxHumidity(new BigDecimal("75"));
        strategy.setOptimalHumidity(new BigDecimal("52"));
        strategy.setIrrigationFactor(BigDecimal.ONE);
        strategy.setFrequencyHint("根据环境自动调整");
        return strategy;
    }
}

package com.agriculture.service.impl;

import com.agriculture.entity.IrrigationThresholdConfig;
import com.agriculture.entity.IrrigationLog;
import com.agriculture.mapper.IrrigationThresholdConfigMapper;
import com.agriculture.service.IrrigationLearningService;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.LocalDateTime;
import java.util.HashMap;
import java.util.Map;

@Slf4j
@Service
@RequiredArgsConstructor
public class IrrigationLearningServiceImpl implements IrrigationLearningService {

    private final IrrigationThresholdConfigMapper configMapper;

    private static final BigDecimal DEFAULT_MOISTURE_GAIN = new BigDecimal("1.5000");
    private static final BigDecimal DEFAULT_EVAPORATION_RATE = new BigDecimal("0.5");
    private static final BigDecimal DEFAULT_TEMP_FACTOR = BigDecimal.ONE;

    private static final double MAX_LEARNING_RATE = 0.3;
    private static final double MIN_LEARNING_RATE = 0.05;

    @Override
    @Transactional
    public void learn(IrrigationLog irrigationLog) {
        if (irrigationLog.getSoilMoistureAfter() == null || irrigationLog.getSoilMoistureBefore() == null) {
            log.debug("灌溉日志缺少湿度数据，跳过学习");
            return;
        }

        if (irrigationLog.getWaterAmount() == null || irrigationLog.getWaterAmount().compareTo(BigDecimal.ZERO) <= 0) {
            log.debug("灌溉日志缺少用水量数据，跳过学习");
            return;
        }

        BigDecimal actualGain = irrigationLog.getSoilMoistureAfter().subtract(irrigationLog.getSoilMoistureBefore());
        if (actualGain.compareTo(BigDecimal.ZERO) <= 0) {
            log.warn("灌溉后湿度未提升，可能存在数据异常");
            return;
        }

        BigDecimal actualGainPerLiter = actualGain.divide(irrigationLog.getWaterAmount(), 4, RoundingMode.HALF_UP);

        updateLearnedMoistureGain(irrigationLog.getPointId(), actualGainPerLiter);

        log.info("学习完成: pointId={}, 实际每升提升湿度={}", irrigationLog.getPointId(), actualGainPerLiter);
    }

    @Override
    public IrrigationThresholdConfig getThresholdConfig(Long pointId) {
        LambdaQueryWrapper<IrrigationThresholdConfig> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(IrrigationThresholdConfig::getPointId, pointId);
        IrrigationThresholdConfig config = configMapper.selectOne(wrapper);

        if (config == null) {
            config = createDefaultConfig(pointId);
        }

        return config;
    }

    @Override
    public BigDecimal getLearnedMoistureGain(Long pointId) {
        IrrigationThresholdConfig config = getThresholdConfig(pointId);
        if (config.getLearnedMoistureGain() != null
                && config.getLearningConfidence() != null
                && config.getLearningConfidence().compareTo(new BigDecimal("0.5")) >= 0) {
            return config.getLearnedMoistureGain();
        }
        return DEFAULT_MOISTURE_GAIN;
    }

    @Override
    public Map<String, BigDecimal> getAllLearnedParams(Long pointId) {
        Map<String, BigDecimal> params = new HashMap<>();
        params.put("MOISTURE_GAIN_PER_LITER", DEFAULT_MOISTURE_GAIN);
        params.put("EVAPORATION_RATE", DEFAULT_EVAPORATION_RATE);
        params.put("TEMP_FACTOR", DEFAULT_TEMP_FACTOR);

        IrrigationThresholdConfig config = getThresholdConfig(pointId);
        if (config != null && config.getLearnedMoistureGain() != null
                && config.getLearningConfidence() != null
                && config.getLearningConfidence().compareTo(new BigDecimal("0.5")) >= 0) {
            params.put("MOISTURE_GAIN_PER_LITER", config.getLearnedMoistureGain());
        }

        return params;
    }

    @Override
    public Map<String, Object> getLearningProgress(Long pointId) {
        Map<String, Object> progress = new HashMap<>();
        IrrigationThresholdConfig config = getThresholdConfig(pointId);

        Map<String, Object> moistureGainInfo = new HashMap<>();
        moistureGainInfo.put("value", config.getLearnedMoistureGain() != null ? config.getLearnedMoistureGain() : DEFAULT_MOISTURE_GAIN);
        moistureGainInfo.put("confidence", config.getLearningConfidence() != null ? config.getLearningConfidence() : new BigDecimal("0.00"));
        moistureGainInfo.put("sampleCount", config.getLearningSampleCount() != null ? config.getLearningSampleCount() : 0);
        progress.put("MOISTURE_GAIN_PER_LITER", moistureGainInfo);

        return progress;
    }

    @Override
    public BigDecimal adjustWaterAmount(Long pointId, BigDecimal baseAmount) {
        BigDecimal moistureGain = getLearnedMoistureGain(pointId);

        BigDecimal adjusted = baseAmount.multiply(DEFAULT_MOISTURE_GAIN)
                .divide(moistureGain, 4, RoundingMode.HALF_UP);

        log.debug("调整用水量: base={}, adjusted={}, moistureGain={}",
                baseAmount, adjusted, moistureGain);

        return adjusted;
    }

    @Transactional
    protected void updateLearnedMoistureGain(Long pointId, BigDecimal newValue) {
        IrrigationThresholdConfig config = getThresholdConfig(pointId);

        int newCount = (config.getLearningSampleCount() != null ? config.getLearningSampleCount() : 0) + 1;
        BigDecimal oldValue = config.getLearnedMoistureGain() != null ? config.getLearnedMoistureGain() : DEFAULT_MOISTURE_GAIN;

        double learningRate = Math.max(MIN_LEARNING_RATE,
                Math.min(MAX_LEARNING_RATE, 1.0 / Math.min(newCount, 10)));

        BigDecimal updatedValue = oldValue.multiply(BigDecimal.valueOf(1 - learningRate))
                .add(newValue.multiply(BigDecimal.valueOf(learningRate)));

        BigDecimal newConfidence = BigDecimal.valueOf(
                Math.min(0.95, 0.30 + newCount * 0.05));

        config.setLearnedMoistureGain(updatedValue.setScale(4, RoundingMode.HALF_UP));
        config.setLearningSampleCount(newCount);
        config.setLearningConfidence(newConfidence.setScale(2, RoundingMode.HALF_UP));
        config.setLastLearningAt(LocalDateTime.now());

        configMapper.updateById(config);

        log.info("更新学习参数: pointId={}, oldValue={}, newValue={}, confidence={}",
                pointId, oldValue, updatedValue, newConfidence);
    }

    private IrrigationThresholdConfig createDefaultConfig(Long pointId) {
        IrrigationThresholdConfig config = new IrrigationThresholdConfig();
        config.setPointId(pointId);
        config.setMoistureThreshold(40);
        config.setMaxSingleIrrigation(180);
        config.setMinIrrigationInterval(30);
        config.setEnablePredictive(1);
        config.setEnableAutoControl(1);
        config.setPredictionMode("ewma");
        config.setLearnedMoistureGain(DEFAULT_MOISTURE_GAIN);
        config.setLearningSampleCount(0);
        config.setLearningConfidence(new BigDecimal("0.00"));

        configMapper.insert(config);
        return config;
    }
}

package com.agriculture.service.impl;

import com.agriculture.entity.SensorData;
import com.agriculture.mapper.SensorDataMapper;
import com.agriculture.model.dto.MoisturePredictionDTO;
import com.agriculture.service.MoisturePredictor;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.LocalDateTime;
import java.util.List;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class MoisturePredictorImpl implements MoisturePredictor {

    private final SensorDataMapper sensorDataMapper;

    private static final double ALPHA = 0.3;
    private static final int TREND_WINDOW = 3;

    @Override
    public MoisturePredictionDTO predict(Long pointId, int hoursAhead) {
        MoisturePredictionDTO result = new MoisturePredictionDTO();

        LocalDateTime startTime = LocalDateTime.now().minusHours(24);
        LocalDateTime endTime = LocalDateTime.now();
        List<SensorData> sensorDataList = sensorDataMapper.findByPointIdAndTimeRange(pointId, startTime, endTime);

        if (sensorDataList == null || sensorDataList.isEmpty()) {
            result.setNeedPreIrrigation(false);
            result.setReason("无历史数据，无法预测");
            result.setConfidence(BigDecimal.ZERO);
            return result;
        }

        List<Double> history = sensorDataList.stream()
                .sorted((a, b) -> a.getRecordedAt().compareTo(b.getRecordedAt()))
                .map(d -> d.getSoilMoisture().doubleValue())
                .collect(Collectors.toList());

        double ewma = calculateEWMA(history);
        double trend = calculateTrend(history);

        double current = history.get(history.size() - 1);
        result.setCurrentMoisture(BigDecimal.valueOf(current).setScale(1, RoundingMode.HALF_UP));

        double predict2h = ewma + trend * 2;
        double predict4h = ewma + trend * 4;
        double predict6h = ewma + trend * 6;

        result.setPredict2h(BigDecimal.valueOf(predict2h).setScale(1, RoundingMode.HALF_UP));
        result.setPredict4h(BigDecimal.valueOf(predict4h).setScale(1, RoundingMode.HALF_UP));
        result.setPredict6h(BigDecimal.valueOf(predict6h).setScale(1, RoundingMode.HALF_UP));

        if (trend > 0.5) {
            result.setTrend("rising");
        } else if (trend < -0.5) {
            result.setTrend("falling");
        } else {
            result.setTrend("stable");
        }

        double confidence = Math.min(0.9, 0.3 + history.size() * 0.02);
        result.setConfidence(BigDecimal.valueOf(confidence).setScale(2, RoundingMode.HALF_UP));

        return result;
    }

    @Override
    public MoisturePredictionDTO analyze(Long pointId, double threshold) {
        MoisturePredictionDTO result = predict(pointId, 4);

        if (result.getCurrentMoisture() == null) {
            return result;
        }

        double current = result.getCurrentMoisture().doubleValue();
        double predict2h = result.getPredict2h() != null ? result.getPredict2h().doubleValue() : current;
        double predict4h = result.getPredict4h() != null ? result.getPredict4h().doubleValue() : current;

        if ("falling".equals(result.getTrend()) && predict2h < threshold && current >= threshold) {
            result.setNeedPreIrrigation(true);
            result.setReason(String.format("预测2小时后湿度将降至%.1f%%，建议提前灌溉", predict2h));
        } else if (predict4h < threshold * 0.9) {
            result.setNeedPreIrrigation(true);
            result.setReason(String.format("预测4小时后湿度将降至%.1f%%，接近临界值", predict4h));
        } else {
            result.setNeedPreIrrigation(false);
            if (current < threshold) {
                result.setReason("当前湿度已低于阈值，需要立即灌溉");
            } else {
                result.setReason("湿度正常，无需预防性灌溉");
            }
        }

        return result;
    }

    @Override
    public double predictValue(Long pointId, int hoursAhead) {
        LocalDateTime startTime = LocalDateTime.now().minusHours(24);
        LocalDateTime endTime = LocalDateTime.now();
        List<SensorData> sensorDataList = sensorDataMapper.findByPointIdAndTimeRange(pointId, startTime, endTime);

        if (sensorDataList == null || sensorDataList.isEmpty()) {
            return -1;
        }

        List<Double> history = sensorDataList.stream()
                .sorted((a, b) -> a.getRecordedAt().compareTo(b.getRecordedAt()))
                .map(d -> d.getSoilMoisture().doubleValue())
                .collect(Collectors.toList());

        double ewma = calculateEWMA(history);
        double trend = calculateTrend(history);

        return ewma + trend * hoursAhead;
    }

    private double calculateEWMA(List<Double> history) {
        if (history.isEmpty()) return 0;

        double ewma = history.get(0);
        for (int i = 1; i < history.size(); i++) {
            ewma = ALPHA * history.get(i) + (1 - ALPHA) * ewma;
        }
        return ewma;
    }

    private double calculateTrend(List<Double> history) {
        if (history.size() < 2) return 0;

        int window = Math.min(TREND_WINDOW, history.size() - 1);
        double trend = 0;

        for (int i = history.size() - window; i < history.size(); i++) {
            trend += history.get(i) - history.get(i - 1);
        }

        return trend / window;
    }
}

