111	    private void checkAndCreateAlarms(SensorData data) {
112	        Long pointId = data.getPointId();
113	
114	        Set<String> existingUnprocessedTypes = new HashSet<>(alarmMapper.findUnprocessedAlarmTypesByPointId(pointId));
115	        List<Alarm> alarmsToCreate = new ArrayList<>();
116	
117	        if (data.getTemperature() != null) {
118	            if (data.getTemperature().compareTo(TEMP_MAX) > 0) {
119	                addAlarmIfNeeded(pointId, "TEMPERATURE_HIGH", data.getTemperature(), TEMP_MAX, existingUnprocessedTypes, alarmsToCreate);
120	            } else if (data.getTemperature().compareTo(TEMP_MIN) < 0) {
121	                addAlarmIfNeeded(pointId, "TEMPERATURE_LOW", data.getTemperature(), TEMP_MIN, existingUnprocessedTypes, alarmsToCreate);
122	            }
123	        }
124	
125	        if (data.getHumidity() != null) {
126	            if (data.getHumidity().compareTo(HUMIDITY_MAX) > 0) {
127	                addAlarmIfNeeded(pointId, "HUMIDITY_HIGH", data.getHumidity(), HUMIDITY_MAX, existingUnprocessedTypes, alarmsToCreate);
128	            } else if (data.getHumidity().compareTo(HUMIDITY_MIN) < 0) {
129	                addAlarmIfNeeded(pointId, "HUMIDITY_LOW", data.getHumidity(), HUMIDITY_MIN, existingUnprocessedTypes, alarmsToCreate);
130	            }
131	        }
132	
133	        if (data.getLight() != null && data.getLight().compareTo(LIGHT_MIN) < 0) {
134	            addAlarmIfNeeded(pointId, "LIGHT_LOW", data.getLight(), LIGHT_MIN, existingUnprocessedTypes, alarmsToCreate);
135	        }
136	
137	        if (data.getCo2() != null && data.getCo2().compareTo(CO2_MAX) > 0) {
138	            addAlarmIfNeeded(pointId, "CO2_HIGH", data.getCo2(), CO2_MAX, existingUnprocessedTypes, alarmsToCreate);
139	        }
140	
141	        if (data.getSoilMoisture() != null && data.getSoilMoisture().compareTo(SOIL_MOISTURE_MIN) < 0) {
142	            addAlarmIfNeeded(pointId, "SOIL_MOISTURE_LOW", data.getSoilMoisture(), SOIL_MOISTURE_MIN, existingUnprocessedTypes, alarmsToCreate);
143	        }
144	
145	        for (Alarm alarm : alarmsToCreate) {
146	            alarmMapper.insert(alarm);
147	            log.warn("创建报警: 检测点={}, 类型={}, 值={}, 阈值={}",
148	                    alarm.getPointId(), alarm.getAlarmType(), alarm.getAlarmValue(), alarm.getThreshold());
149	        }
150	    }
151	
152	    private void addAlarmIfNeeded(Long pointId, String alarmType, BigDecimal alarmValue, BigDecimal threshold,
153	                                  Set<String> existingUnprocessedTypes, List<Alarm> alarmsToCreate) {
154	        if (existingUnprocessedTypes.contains(alarmType)) {
155	            return;
156	        }
157	
158	        Alarm alarm = new Alarm();
159	        alarm.setPointId(pointId);
160	        alarm.setAlarmType(alarmType);
161	        alarm.setAlarmValue(alarmValue);
162	        alarm.setThreshold(threshold);
163	        alarm.setStatus(0);
164	
165	        alarmsToCreate.add(alarm);
166	        existingUnprocessedTypes.add(alarmType);
167	    }
