120	    @Override
121	    public AutoIrrigationPlanResponse buildAutoPlan(EnvironmentDataDTO envData, IrrigationPlanConfig config) {
122	        AutoIrrigationPlanResponse plan = new AutoIrrigationPlanResponse();
123	
124	        if (envData == null || envData.getSoilMoisture() == null) {
125	            plan.setShouldIrrigate(false);
126	            plan.setWaterAmountL(BigDecimal.ZERO);
127	            plan.setDurationSeconds(0);
128	            plan.setTargetMoisture(BigDecimal.ZERO);
129	            plan.setMoistureGap(BigDecimal.ZERO);
130	            plan.setRiskFactor(BigDecimal.ONE);
131	            plan.setReason("缺少环境数据");
132	            return plan;
133	        }
134	
135	        int threshold = 40;
136	        if (config != null && config.getMoistureThreshold() != null) {
137	            threshold = clamp(config.getMoistureThreshold(), 20, 70);
138	        }
139	
140	        BigDecimal soilMoisture = clamp(envData.getSoilMoisture(), BigDecimal.ZERO, new BigDecimal("100"));
141	        if (soilMoisture.compareTo(new BigDecimal(threshold)) >= 0) {
142	            return buildNoIrrigationPlan(threshold, "土壤水分超过阈值");
143	        }
144	
145	        BigDecimal targetMoisture = new BigDecimal(threshold + 12).min(new BigDecimal("75"));
146	        BigDecimal moistureGap = targetMoisture.subtract(soilMoisture).max(BigDecimal.ZERO);
147	
148	        BigDecimal baseWaterAmount = moistureGap.divide(SOIL_MOISTURE_GAIN_PER_LITER, 6, RoundingMode.HALF_UP);
149	        BigDecimal riskFactor = BigDecimal.ONE;
150	
151	        if (envData.getTemperature() != null) {
152	            if (envData.getTemperature().compareTo(new BigDecimal("35")) > 0) {
153	                riskFactor = riskFactor.add(new BigDecimal("0.2"));
154	            } else if (envData.getTemperature().compareTo(new BigDecimal("30")) > 0) {
155	                riskFactor = riskFactor.add(new BigDecimal("0.1"));
156	            } else if (envData.getTemperature().compareTo(new BigDecimal("15")) < 0) {
157	                riskFactor = riskFactor.subtract(new BigDecimal("0.08"));
158	            }
159	        }
160	
161	        if (envData.getHumidity() != null) {
162	            if (envData.getHumidity().compareTo(new BigDecimal("40")) < 0) {
163	                riskFactor = riskFactor.add(new BigDecimal("0.1"));
164	            } else if (envData.getHumidity().compareTo(new BigDecimal("75")) > 0) {
165	                riskFactor = riskFactor.subtract(new BigDecimal("0.08"));
166	            }
167	        }
168	
169	        if (envData.getLight() != null) {
170	            if (envData.getLight().compareTo(new BigDecimal("30000")) > 0) {
171	                riskFactor = riskFactor.add(new BigDecimal("0.15"));
172	            } else if (envData.getLight().compareTo(new BigDecimal("15000")) > 0) {
173	                riskFactor = riskFactor.add(new BigDecimal("0.08"));
174	            } else if (envData.getLight().compareTo(new BigDecimal("1000")) < 0) {
175	                riskFactor = riskFactor.subtract(new BigDecimal("0.05"));
176	            }
177	        }
178	
179	        if (envData.getCo2() != null && envData.getCo2().compareTo(new BigDecimal("1000")) > 0) {
180	            riskFactor = riskFactor.add(new BigDecimal("0.05"));
181	        }
182	
183	        riskFactor = clamp(riskFactor, new BigDecimal("0.75"), new BigDecimal("1.45"));
184	        BigDecimal waterAmount = baseWaterAmount.multiply(riskFactor);
185	        waterAmount = clamp(waterAmount, new BigDecimal("0.5"), new BigDecimal("45"));
186	
187	        int rawDuration = waterAmount.divide(WATER_PER_SECOND, 0, RoundingMode.HALF_UP).intValue();
188	        int durationSeconds = clamp(rawDuration, MIN_AUTO_DURATION_SEC, MAX_AUTO_DURATION_SEC);
189	
190	        plan.setShouldIrrigate(true);
191	        plan.setWaterAmountL(waterAmount.setScale(1, RoundingMode.HALF_UP));
192	        plan.setDurationSeconds(durationSeconds);
193	        plan.setTargetMoisture(targetMoisture.setScale(1, RoundingMode.HALF_UP));
194	        plan.setMoistureGap(moistureGap.setScale(1, RoundingMode.HALF_UP));
195	        plan.setRiskFactor(riskFactor.setScale(2, RoundingMode.HALF_UP));
196	        plan.setReason("根据环境和门槛自动计划");
197	        return plan;
198	    }
