207	    @Override
208	    @Transactional
209	    public AutoIrrigationResultResponse startAutoIrrigation(AutoIrrigationRequest request) {
210	        Long pointId = request != null ? request.getPointId() : null;
211	        EnvironmentDataDTO envData = request != null ? request.getEnvData() : null;
212	        IrrigationPlanConfig config = request != null ? request.getConfig() : null;
213	
214	        if (pointId == null) {
215	            pointId = 1L;
216	        }
217	
218	        AutoIrrigationPlanResponse plan = buildAutoPlan(envData, config);
219	
220	        if (config == null || config.getAutoMode() == null || !config.getAutoMode()) {
221	            plan.setShouldIrrigate(false);
222	            plan.setReason("自动模式已禁用");
223	        }
224	
225	        if (plan.isShouldIrrigate() && isCurrentlyIrrigating(pointId)) {
226	            plan.setShouldIrrigate(false);
227	            plan.setReason("灌溉系统已经开始运行");
228	        }
229	
230	        if (plan.isShouldIrrigate()) {
231	            int minInterval = config != null && config.getMinInterval() != null ? config.getMinInterval() : 0;
232	            if (!isAutoIntervalOk(pointId, minInterval)) {
233	                plan.setShouldIrrigate(false);
234	                plan.setReason("最短间隔尚未过去");
235	            }
236	        }
237	
238	        AutoIrrigationResultResponse result = new AutoIrrigationResultResponse();
239	        result.setPlan(plan);
240	
241	        if (plan.isShouldIrrigate()) {
242	            IrrigationLog logEntity = startIrrigationInternal(pointId, plan.getDurationSeconds(), 0);
243	            result.setLog(toDTO(logEntity));
244	            result.setStarted(true);
245	        } else {
246	            result.setStarted(false);
247	            result.setLog(null);
248	        }
249	
250	        return result;
251	    }
252	
253	    private IrrigationLog startIrrigationInternal(Long pointId, Integer duration, Integer mode) {
254	        IrrigationLog irrigationLog = new IrrigationLog();
255	        irrigationLog.setPointId(pointId);
256	        irrigationLog.setDuration(duration);
257	        irrigationLog.setMode(mode);
258	        irrigationLog.setStartTime(LocalDateTime.now());
259	
260	        BigDecimal waterAmount = WATER_PER_SECOND.multiply(new BigDecimal(duration));
261	        irrigationLog.setWaterAmount(waterAmount);
262	
263	        irrigationLogMapper.insert(irrigationLog);
264	        log.info("灌溉开始： pointId={}， durationSec={}， waterAmountL={}， mode={}",
265	                pointId, duration, waterAmount, mode);
266	        return irrigationLog;
267	    }
268	
269	    private boolean isCurrentlyIrrigating(Long pointId) {
270	        IrrigationLog active = irrigationLogMapper.findActiveByPointId(pointId);
271	        return active != null;
272	    }
273	
274	    private boolean isAutoIntervalOk(Long pointId, int minIntervalSeconds) {
275	        if (minIntervalSeconds <= 0) {
276	            return true;
277	        }
278	
279	        IrrigationLog lastAuto = irrigationLogMapper.findLastAutoByPointId(pointId);
280	        if (lastAuto == null || lastAuto.getStartTime() == null) {
281	            return true;
282	        }
283	
284	        Duration elapsed = Duration.between(lastAuto.getStartTime(), LocalDateTime.now());
285	        return elapsed.getSeconds() >= minIntervalSeconds;
286	    }
287	
288	    private AutoIrrigationPlanResponse buildNoIrrigationPlan(int targetMoisture, String reason) {
289	        AutoIrrigationPlanResponse plan = new AutoIrrigationPlanResponse();
290	        plan.setShouldIrrigate(false);
291	        plan.setWaterAmountL(BigDecimal.ZERO);
292	        plan.setDurationSeconds(0);
293	        plan.setTargetMoisture(new BigDecimal(targetMoisture).setScale(1, RoundingMode.HALF_UP));
294	        plan.setMoistureGap(BigDecimal.ZERO);
295	        plan.setRiskFactor(BigDecimal.ONE);
296	        plan.setReason(reason);
297	        return plan;
298	    }
299	
300	    private int clamp(int value, int min, int max) {
301	        return Math.max(min, Math.min(max, value));
302	    }
